item.description:
 &lt;h1 id=&#34;1、aria2开机启动文件配置—aria2-service&#34;&gt;&lt;a href=&#34;#1、aria2开机启动文件配置—aria2-service&#34; class=&#34;headerlink&#34; title=&#34;1、aria2开机启动文件配置—aria2.service&#34;&gt;&lt;/a&gt;1、aria2开机启动文件配置—&lt;code&gt;aria2.service&lt;/code&gt;&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;k@yk-pc:~$ sudo nano /usr/lib/systemd/system/aria2.service&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;输入以下内容：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[Unit]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Description=Aria2 Service&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;After=network.target&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Service]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStart=/usr/bin/aria2c --conf-path=/etc/aria2/aria2.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Install]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;WantedBy=default.target&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;写入&lt;code&gt;ctrl+o&lt;/code&gt;，保存 &lt;code&gt;Enter&lt;/code&gt;，退出&lt;code&gt;ctrl+x&lt;/code&gt;&lt;br&gt;拷贝到&lt;code&gt;/etc/systemd/user&lt;/code&gt; 目录下&lt;br&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;k@yk-pc:~$ sudo cp /usr/lib/systemd/system/aria2.service /etc/systemd/system&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;2-设置开机启动&#34;&gt;&lt;a href=&#34;#2-设置开机启动&#34; class=&#34;headerlink&#34; title=&#34;2.设置开机启动&#34;&gt;&lt;/a&gt;2.设置开机启动&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/usr/lib/systemd/system$ systemctl &lt;span class=&#34;built_in&#34;&gt;enable&lt;/span&gt; aria2.service&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;提示&lt;code&gt;Created symlink /etc/systemd/system/default.target.wants/aria2.service → /etc/systemd/system/aria2.service.&lt;/code&gt;设置成功&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://github.com/P3TERX/aria2.conf&#34;&gt;一键安装及配置开源项目：&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt; service命令其实是去/etc/init.d目录下,去执行相关程序,相应脚本需要自己填写。  &lt;/p&gt;
&lt;h1 id=&#34;1-设置nginx启动脚本&#34;&gt;&lt;a href=&#34;#1-设置nginx启动脚本&#34; class=&#34;headerlink&#34; title=&#34;1.设置nginx启动脚本&#34;&gt;&lt;/a&gt;1.设置nginx启动脚本&lt;/h1&gt;&lt;p&gt;在&lt;code&gt;/etc/init.d/&lt;/code&gt;目录下创建&lt;code&gt;nginx&lt;/code&gt;的启动文件&lt;br&gt;命令 &lt;code&gt;vim /etc/init.d/nginx&lt;/code&gt;，将以下代码复制进去保存即可&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;#!/bin/bash&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# nginx Startup script for the Nginx HTTP Server&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# it is v.0.0.2 version.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# chkconfig: - 85 15&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# description: Nginx is a high-performance web and proxy server.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#              It has a lot of features, but it&amp;#x27;s not for everyone.&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# processname: nginx&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# pidfile: /var/run/nginx.pid&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# config: /usr/local/nginx/conf/nginx.conf&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;nginx=/usr/&lt;span class=&#34;built_in&#34;&gt;local&lt;/span&gt;/nginx/sbin/nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;conf=/usr/&lt;span class=&#34;built_in&#34;&gt;local&lt;/span&gt;/nginx/conf/nginx.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;case&lt;/span&gt; &lt;span class=&#34;variable&#34;&gt;$1&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;start)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; -n &lt;span class=&#34;string&#34;&gt;&amp;quot;Starting Nginx&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$nginx&lt;/span&gt; -c &lt;span class=&#34;variable&#34;&gt;$conf&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot; done.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;stop)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; -n &lt;span class=&#34;string&#34;&gt;&amp;quot;Stopping Nginx&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;killall -9 nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot; done.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;test&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$nginx&lt;/span&gt; -t -c &lt;span class=&#34;variable&#34;&gt;$conf&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Success.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;reload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; -n &lt;span class=&#34;string&#34;&gt;&amp;quot;Reloading Nginx&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ps auxww | grep nginx | grep master | awk &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;#123;print $2&amp;#125;&amp;#x27;&lt;/span&gt; | xargs &lt;span class=&#34;built_in&#34;&gt;kill&lt;/span&gt; -HUP&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot; done.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;restart)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$nginx&lt;/span&gt; -s reload&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;reload done.&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Usage: &lt;span class=&#34;variable&#34;&gt;$0&lt;/span&gt; &amp;#123;start|restart|reload|stop|test|show&amp;#125;&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;esac&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;2-设置文件权限并启动Nginx&#34;&gt;&lt;a href=&#34;#2-设置文件权限并启动Nginx&#34; class=&#34;headerlink&#34; title=&#34;2. 设置文件权限并启动Nginx&#34;&gt;&lt;/a&gt;2. 设置文件权限并启动Nginx&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;chkconfig --add /etc/init.d/nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chmod 755 /etc/init.d/nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chkconfig --add nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;service nginx start &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;3-设置开机启动&#34;&gt;&lt;a href=&#34;#3-设置开机启动&#34; class=&#34;headerlink&#34; title=&#34;3.设置开机启动&#34;&gt;&lt;/a&gt;3.设置开机启动&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/sbin/chkconfig --level 345 nginx on&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;4-其他命令介绍&#34;&gt;&lt;a href=&#34;#4-其他命令介绍&#34; class=&#34;headerlink&#34; title=&#34;4. 其他命令介绍&#34;&gt;&lt;/a&gt;4. 其他命令介绍&lt;/h1&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;chkconfig --list 查看全部服务状态&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;例如:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;运行chkconfig --list httpd&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;看自动启动状态&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;httpd 0:off 1:off 2:off 3:on 4:on 5:on 6:off&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;0~6是指运行级别，一般服务器都运行在3这个级别上。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;添加为自动启动&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chkconfig --add httpd&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;或者指定运行级别&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chkconfig --level 345 httpd on&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;停止自动启动&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chkconfig --del httpd&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;或指定运行级别&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;chkconfig --level 345 httpd off&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;参考资料：&lt;br&gt;1.&lt;a href=&#34;https://www.cnblogs.com/seasen/p/12603017.html&#34;&gt;nginx添加service以及随开机启动:&lt;/a&gt;&lt;br&gt;2.&lt;a href=&#34;https://blog.csdn.net/chuifuhuo6864/article/details/100876188&#34;&gt;linux 命令 /sbin/chkconfig&lt;/a&gt;&lt;br&gt;3.&lt;a href=&#34;https://www.cnblogs.com/donglovebobo/p/14052728.html&#34;&gt;nginx加入到service服务 systemctl安装nginx 自启动&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;linux服务目前主要有service和systemctl两种管理方式，systemd是Linux系统最新的初始化系统(init),作用是提高系统的启动速度，尽可能启动较少的进程，尽可能更多进程并发启动，对应的进程管理命令是systemctl。  &lt;/p&gt;
&lt;h1 id=&#34;1-建立服务文件&#34;&gt;&lt;a href=&#34;#1-建立服务文件&#34; class=&#34;headerlink&#34; title=&#34;1. 建立服务文件&#34;&gt;&lt;/a&gt;1. 建立服务文件&lt;/h1&gt;&lt;p&gt;命令 &lt;code&gt;vim /usr/lib/systemd/system/nginx.service&lt;/code&gt;，进入文件，将以下代码复制进去保存即可&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[Unit]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Description=nginx  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;After=network.target  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Service]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Type=forking&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStart=/usr/&lt;span class=&#34;built_in&#34;&gt;local&lt;/span&gt;/nginx/sbin/nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecReload=/bin/&lt;span class=&#34;built_in&#34;&gt;kill&lt;/span&gt; -s reload&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStop=/bin/&lt;span class=&#34;built_in&#34;&gt;kill&lt;/span&gt; -s stop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;PrivateTmp=&lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Install]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;WantedBy=multi-user.target&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;参数说明：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[Unit]:服务的说明&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Description=:描述服务&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;After=:描述服务类别&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Service]服务运行参数的设置&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Type=forking是后台运行的形式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStart=为服务的具体运行命令&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecReload=为重启命令&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStop=为停止命令&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;PrivateTmp=True表示给服务分配独立的临时空间&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;注意：启动、重启、停止命令全部要求使用绝对路径&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Install]服务安装的相关设置，可设置为多用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;WantedBy=multi-user.target&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;2-设置文件权限并使文件生效&#34;&gt;&lt;a href=&#34;#2-设置文件权限并使文件生效&#34; class=&#34;headerlink&#34; title=&#34;2. 设置文件权限并使文件生效&#34;&gt;&lt;/a&gt;2. 设置文件权限并使文件生效&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo chmod 755 /usr/lib/systemd/system/nginx.service&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl daemon-reload&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;3-设置开机启动&#34;&gt;&lt;a href=&#34;#3-设置开机启动&#34; class=&#34;headerlink&#34; title=&#34;3.设置开机启动&#34;&gt;&lt;/a&gt;3.设置开机启动&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;systemctl &lt;span class=&#34;built_in&#34;&gt;enable&lt;/span&gt; nginx.service&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;只有返回类似 &lt;code&gt;Created symlink from /etc/systemd/system/multi-user.target.wants/nginx.service → /etc/systemd/system/nginx.service&lt;/code&gt;提示才能够确定设置成功。如果不是请检查上面的文件.  &lt;/p&gt;
&lt;h1 id=&#34;4-其他命令&#34;&gt;&lt;a href=&#34;#4-其他命令&#34; class=&#34;headerlink&#34; title=&#34;4. 其他命令&#34;&gt;&lt;/a&gt;4. 其他命令&lt;/h1&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;systemctl is-enabled servicename.service &lt;span class=&#34;comment&#34;&gt;#查询服务是否开机启动&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl &lt;span class=&#34;built_in&#34;&gt;enable&lt;/span&gt; *.service &lt;span class=&#34;comment&#34;&gt;#开机运行服务&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl &lt;span class=&#34;built_in&#34;&gt;disable&lt;/span&gt; *.service &lt;span class=&#34;comment&#34;&gt;#取消开机运行&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl start *.service &lt;span class=&#34;comment&#34;&gt;#启动服务&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl stop *.service &lt;span class=&#34;comment&#34;&gt;#停止服务&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl restart *.service &lt;span class=&#34;comment&#34;&gt;#重启服务&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl reload *.service &lt;span class=&#34;comment&#34;&gt;#重新加载服务配置文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl status *.service &lt;span class=&#34;comment&#34;&gt;#查询服务运行状态&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;systemctl --failed &lt;span class=&#34;comment&#34;&gt;#显示启动失败的服务&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;转载于&lt;a href=&#34;https://blog.csdn.net/ren365880/article/details/103597006&#34;&gt;nginx在systemctl方式开机自启动&lt;/a&gt;&lt;br&gt;参考资料：  &lt;/p&gt;
&lt;p&gt;1.&lt;a href=&#34;https://www.cnblogs.com/seasen/p/12603017.html&#34;&gt;nginx添加service以及随开机启动:&lt;/a&gt;  &lt;/p&gt;

 &lt;h1 id=&#34;Debian-环境安装新版-nginx及配置webdav&#34;&gt;&lt;a href=&#34;#Debian-环境安装新版-nginx及配置webdav&#34; class=&#34;headerlink&#34; title=&#34;Debian 环境安装新版 nginx及配置webdav&#34;&gt;&lt;/a&gt;Debian 环境安装新版 nginx及配置webdav&lt;/h1&gt;&lt;h2 id=&#34;一、Nginx用源安装最新稳定版&#34;&gt;&lt;a href=&#34;#一、Nginx用源安装最新稳定版&#34; class=&#34;headerlink&#34; title=&#34;一、Nginx用源安装最新稳定版&#34;&gt;&lt;/a&gt;一、Nginx用源安装最新稳定版&lt;/h2&gt;&lt;h2 id=&#34;二、源码编译安装最新稳定版：&#34;&gt;&lt;a href=&#34;#二、源码编译安装最新稳定版：&#34; class=&#34;headerlink&#34; title=&#34;二、源码编译安装最新稳定版：&#34;&gt;&lt;/a&gt;二、源码编译安装最新稳定版：&lt;/h2&gt;&lt;h2 id=&#34;三、配置webdav模块&#34;&gt;&lt;a href=&#34;#三、配置webdav模块&#34; class=&#34;headerlink&#34; title=&#34;三、配置webdav模块&#34;&gt;&lt;/a&gt;三、配置webdav模块&lt;/h2&gt;&lt;p&gt; （1）配置webdav&lt;br&gt; （2）设置webdav帐号和密码：&lt;br&gt; （3）挂载到坚果云方法&lt;br&gt; （4）nginx加入到systemctl服务运行&lt;br&gt; （5）常用命令&lt;/p&gt;
&lt;h2 id=&#34;四、手机用的连接为webdav软件：&#34;&gt;&lt;a href=&#34;#四、手机用的连接为webdav软件：&#34; class=&#34;headerlink&#34; title=&#34;四、手机用的连接为webdav软件：&#34;&gt;&lt;/a&gt;四、手机用的连接为webdav软件：&lt;/h2&gt;&lt;h2 id=&#34;五、一些问题及解决方法&#34;&gt;&lt;a href=&#34;#五、一些问题及解决方法&#34; class=&#34;headerlink&#34; title=&#34;五、一些问题及解决方法&#34;&gt;&lt;/a&gt;五、一些问题及解决方法&lt;/h2&gt;&lt;h2 id=&#34;一、Nginx用源安装最新稳定版-1&#34;&gt;&lt;a href=&#34;#一、Nginx用源安装最新稳定版-1&#34; class=&#34;headerlink&#34; title=&#34;一、Nginx用源安装最新稳定版&#34;&gt;&lt;/a&gt;一、Nginx用源安装最新稳定版&lt;/h2&gt;&lt;p&gt;参见文章：&lt;a href=&#34;https://debian.cn/articles/466?www&#34;&gt;Debian 环境安装新版 nginx :&lt;/a&gt;&lt;br&gt;在 &lt;code&gt;Debian&lt;/code&gt; 系统中，我们可以通过 &lt;code&gt;apt-get&lt;/code&gt; 安装系统自带的 &lt;code&gt;nginx&lt;/code&gt;，这样安装的 &lt;code&gt;nginx&lt;/code&gt; 版本略旧。&lt;code&gt;Nginx&lt;/code&gt; 官网提供了一些编辑绎好的 &lt;code&gt;deb&lt;/code&gt; 安装包，我们只需更新安装源，就可以通过 &lt;code&gt;apt-get&lt;/code&gt; 来安装最新的稳定版 &lt;code&gt;Nginx&lt;/code&gt;了。&lt;/p&gt;
&lt;p&gt;加载安装源并导入key&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ echo deb http://nginx.org/packages/debian/ stretch nginx | sudo tee /etc/apt/sources.list.d/nginx.list &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ wget http://nginx.org/keys/nginx_signing.key &amp;amp;&amp;amp; sudo apt-key add nginx_signing.key &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ sudo apt update &amp;amp;&amp;amp; apt install nginx -y &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;到这一部分就完成了最新稳定版的 &lt;code&gt;Nginx&lt;/code&gt; 的安装。&lt;/p&gt;
&lt;p&gt;&lt;em&gt;需要注意的是，这一步安装的 Nginx 和系统自带的 nginx 的配置目录略有区别，可以用一下几个简单的命令修正&lt;/em&gt;：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo mkdir /etc/nginx/&amp;#123;sites-available,sites-enabled&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo mv /etc/nginx/conf.d/* /etc/nginx/sites-available&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo rmdir -f /etc/nginx/conf.d/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo perl -pi -e &amp;#x27;s/conf.d/sites-enabled/g&amp;#x27; /etc/nginx/nginx.conf&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;其他问题：&lt;br&gt;&lt;code&gt;bash: nginx：未找到命令&lt;/code&gt;&lt;br&gt;由于shell命令基本都在&lt;code&gt;/usr/bin&lt;/code&gt;，&lt;code&gt;/usr/sbin&lt;/code&gt;，&lt;code&gt;/bin&lt;/code&gt;，&lt;code&gt;/sbin&lt;/code&gt;，&lt;code&gt;/usr/X11R6/bin&lt;/code&gt;中有定义。&lt;br&gt;所以，只要把这些命令重新取出来就能使用了，也算是个补救的办法。&lt;br&gt;&lt;code&gt;export PATH=/usr/bin:/usr/sbin:/bin:/sbin:/usr/X11R6/bin&lt;/code&gt;&lt;br&gt;转载于:&lt;a href=&#34;https://www.cnblogs.com/young233/p/10879077.html&#34;&gt;修改profile导致bash不能用的补救方法&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;二、源码编译安装最新稳定版：-1&#34;&gt;&lt;a href=&#34;#二、源码编译安装最新稳定版：-1&#34; class=&#34;headerlink&#34; title=&#34;二、源码编译安装最新稳定版：&#34;&gt;&lt;/a&gt;二、源码编译安装最新稳定版：&lt;/h2&gt;&lt;p&gt;&lt;a href=&#34;http://nginx.org/download/nginx-1.20.1.tar.gz&#34;&gt;nginx1.20.1下载地址：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/arut/nginx-dav-ext-module/archive/refs/tags/v3.0.0.tar.gz&#34;&gt;nginx-dav-ext-module v3.0.0下载地址：&lt;/a&gt;  &lt;/p&gt;
&lt;h3 id=&#34;1-卸载并清理安装的nginx&#34;&gt;&lt;a href=&#34;#1-卸载并清理安装的nginx&#34; class=&#34;headerlink&#34; title=&#34;1. 卸载并清理安装的nginx&#34;&gt;&lt;/a&gt;1. 卸载并清理安装的nginx&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ sudo apt autoremove nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ sudo apt purge nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ sudo apt clean&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-下载并编译安装&#34;&gt;&lt;a href=&#34;#2-下载并编译安装&#34; class=&#34;headerlink&#34; title=&#34;2. 下载并编译安装&#34;&gt;&lt;/a&gt;2. 下载并编译安装&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/下载/压缩包$ tar zxvf nginx-1.21.0.tar.gz&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/下载/压缩包$ tar zxvf nginx-dav-ext-module-3.0.0.tar.gz -C /home/yk/下载/压缩包/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/下载/压缩包$ tar zxvf nginx-1.21.0.tar.gz -C /home/yk/下载/压缩包/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/下载/压缩包$ cd nginx-1.21.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/下载/压缩包$ sudo apt-get install libpcre3 libpcre3-dev zlib1g-dev openssl libssl-dev libxslt-dev libgd-dev libgeoip-dev apache2-utils&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/下载/压缩包/nginx-1.21.0$ su root&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;密码：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;root@yk-pc:/home/yk/下载/压缩包/nginx-1.21.0#  ./configure --prefix=/etc/nginx --with-http_dav_module --with-http_stub_status_module --with-http_flv_module --with-http_gzip_static_module --with-stream --with-stream=dynamic --with-http_realip_module --with-http_v2_module --with-http_image_filter_module  --with-http_image_filter_module=dynamic --with-http_ssl_module --add-module=/home/yk/下载/压缩包/nginx-dav-ext-module-3.0.0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;root@yk-pc:/home/yk/下载/压缩包/nginx-1.21.0# make &amp;amp;&amp;amp; make install&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;root@yk-pc:/etc/nginx#  ln -s /etc/nginx/sbin/nginx /usr/bin/nginx &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
