an class=&#34;line&#34;&gt;129&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;130&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;131&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;132&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;133&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;134&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;135&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;136&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;137&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;138&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;139&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;140&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;141&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;142&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;143&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;144&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;145&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;146&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;147&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;148&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;149&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;150&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;151&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;152&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;153&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#user  nobody;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;worker_processes  1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#error_log  logs/error.log;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#error_log  logs/error.log  notice;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#error_log  logs/error.log  info;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#pid        logs/nginx.pid;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;events &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    worker_connections  1024;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;http &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    include       mime.types;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    default_type  application/octet-stream;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    log_format  main  &amp;#x27;$remote_addr - $remote_user [$time_local] &amp;quot;$request&amp;quot; &amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &amp;#x27;$status $body_bytes_sent &amp;quot;$http_referer&amp;quot; &amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                      &amp;#x27;&amp;quot;$http_user_agent&amp;quot; &amp;quot;$http_x_forwarded_for&amp;quot;&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    access_log  logs/access.log  main;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    sendfile        on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tcp_nopush     on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #keepalive_timeout  0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    keepalive_timeout  65;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    gzip  on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    server &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        listen       80;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        server_name  localhost;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        #charset koi8-r;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        access_log  logs/host.access.log  main;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        location / &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            root   html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            index  index.html index.htm;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        error_page  404              /404.html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        # redirect server error pages to the static page /50x.html&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        #&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       error_page   500 502 503 504  /50x.html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        location = /50x.html &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            root   html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        # proxy the PHP scripts to Apache listening on 127.0.0.1:80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        #&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        location ~ \.php$ &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            proxy_pass   http://127.0.0.1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        # pass the PHP scripts to FastCGI server listening on 127.0.0.1:9000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        #&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        location ~ \.php$ &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            root           html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            fastcgi_pass   127.0.0.1:9000;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            fastcgi_index  index.php;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            fastcgi_param  SCRIPT_FILENAME  /scripts$fastcgi_script_name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            include        fastcgi_params;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        # deny access to .htaccess files, if Apache&amp;#x27;s document root&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        # concurs with nginx&amp;#x27;s one&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        #&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        location ~ /\.ht &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            deny  all;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # another virtual host using mix of IP-, name-, and port-based configuration&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #server &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    listen       8000;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    listen       somename:8080;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    server_name  somename  alias  another.alias;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    location / &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #        root   html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #        index  index.html index.htm;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      server&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          listen    81;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          server_name webdav;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          error_log /etc/nginx/logs/webdav.error.log error;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          access_log  /etc/nginx/logs/webdav.access.log combined;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       location / &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             root /home/yk/www/nginx/webdav;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             charset utf-8;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             autoindex on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             dav_methods  PUT DELETE MKCOL COPY MOVE;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             dav_ext_methods PROPFIND OPTIONS;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             create_full_put_path on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             dav_access user:rw group:r all:r;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             auth_basic &amp;quot;Authorized Users Only&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             auth_basic_user_file /etc/nginx/.htpasswd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             client_max_body_size 5G;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           error_page   500 502 503 504  /50x.html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;           location = /50x.html &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;               root   /etc/nginx/html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;server &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    listen 8080;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    error_log /etc/nginx/logs/jianguoyun.error.log error;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    access_log  /etc/nginx/logs/jianguoyun.access.log combined;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    location / &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        root /home/yk/www/nginx/jianguoyun;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        autoindex on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        dav_methods PUT DELETE MKCOL COPY MOVE;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        dav_ext_methods PROPFIND OPTIONS;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        create_full_put_path on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        dav_access user:rw group:r all:r;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        auth_basic &amp;quot;Authorized Users Only&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        auth_basic_user_file /etc/nginx/.htpasswd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    # HTTPS server&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #server &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    listen       443 ssl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    server_name  localhost;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    ssl_certificate      cert.pem;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    ssl_certificate_key  cert.key;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    ssl_session_cache    shared:SSL:1m;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    ssl_session_timeout  5m;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    ssl_ciphers  HIGH:!aNULL:!MD5;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    ssl_prefer_server_ciphers  on;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    location / &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #        root   html;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #        index  index.html index.htm;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    #&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;（2）设置webdav帐号和密码：&#34;&gt;&lt;a href=&#34;#（2）设置webdav帐号和密码：&#34; class=&#34;headerlink&#34; title=&#34;（2）设置webdav帐号和密码：&#34;&gt;&lt;/a&gt;（2）设置webdav帐号和密码：&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;root@yk-pc:/etc/nginx# echo -n &amp;#x27;yk:&amp;#x27; | tee /etc/nginx/.htpasswd&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk:root@yk-pc:/etc/nginx# openssl passwd -apr1 | tee -a /etc/nginx/.htpasswd&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Password: &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Verifying - Password: &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$apr1$6aLRK.3F$gg76W8E9vT65vn1cE/Mk41&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;（3）挂载到坚果云方法&#34;&gt;&lt;a href=&#34;#（3）挂载到坚果云方法&#34; class=&#34;headerlink&#34; title=&#34;（3）挂载到坚果云方法&#34;&gt;&lt;/a&gt;（3）挂载到坚果云方法&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ sudo apt-get install davfs2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ mkdir -p /home/yk/www/nginx/jianguoyun&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ sudo vim  /etc/davfs2/davfs2.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#ignore_dav_header 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;  改为：&lt;br&gt;&lt;code&gt;ignore_dav_header 1&lt;/code&gt;&lt;br&gt;  挂载：&lt;br&gt;&lt;code&gt;yk@yk-pc:~$ sudo mount -t davfs https://dav.jianguoyun.com/dav/ /home/yk/www/nginx/jianguoyun&lt;/code&gt;&lt;br&gt;取消挂载：&lt;br&gt;&lt;code&gt;yk@yk-pc:~$ sudo fusermount -u /home/yk/www/nginx/jianguoyun&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;（4）nginx加入到systemctl服务运行&#34;&gt;&lt;a href=&#34;#（4）nginx加入到systemctl服务运行&#34; class=&#34;headerlink&#34; title=&#34;（4）nginx加入到systemctl服务运行&#34;&gt;&lt;/a&gt;（4）&lt;code&gt;nginx&lt;/code&gt;加入到&lt;code&gt;systemctl&lt;/code&gt;服务运行&lt;/h3&gt;&lt;p&gt;  &lt;code&gt;yk@yk-pc:~$ sudo vim /usr/lib/systemd/system/nginx.service&lt;/code&gt;&lt;br&gt;输入以下内容并保存&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[Unit]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Description=nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;After=network.target&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Service]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Type=forking&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;PIDFile=/etc/nginx/logs/nginx.pid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStart=/etc/nginx/sbin/nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecReload=/etc/nginx/sbin/nginx -s reload&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStop=/etc/nginx/sbin/nginx -s stop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;PrivateTmp=true&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Install]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;WantedBy=multi-user.target&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;（5）常用命令：&#34;&gt;&lt;a href=&#34;#（5）常用命令：&#34; class=&#34;headerlink&#34; title=&#34;（5）常用命令：&#34;&gt;&lt;/a&gt;（5）常用命令：&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ systemctl daemon-reload&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~$ systemctl start/stop/reload nginx&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;四、手机用的连接为webdav软件：-1&#34;&gt;&lt;a href=&#34;#四、手机用的连接为webdav软件：-1&#34; class=&#34;headerlink&#34; title=&#34;四、手机用的连接为webdav软件：&#34;&gt;&lt;/a&gt;四、手机用的连接为webdav软件：&lt;/h2&gt;&lt;p&gt;   &lt;strong&gt;苹果：FE文件管理器、ES文件浏览器&lt;/strong&gt;&lt;br&gt;   &lt;strong&gt;安卓：CX文件管理器、ES文件浏览器&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;五、一些问题及解决方法：&#34;&gt;&lt;a href=&#34;#五、一些问题及解决方法：&#34; class=&#34;headerlink&#34; title=&#34;五、一些问题及解决方法：&#34;&gt;&lt;/a&gt;五、一些问题及解决方法：&lt;/h2&gt;&lt;h3 id=&#34;1-查找进程：&#34;&gt;&lt;a href=&#34;#1-查找进程：&#34; class=&#34;headerlink&#34; title=&#34;1. 查找进程：&#34;&gt;&lt;/a&gt;1. 查找进程：&lt;/h3&gt;&lt;p&gt;  查询端口：&lt;br&gt;  &lt;code&gt;ps -ef |grep nginx&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;2-开放端口：&#34;&gt;&lt;a href=&#34;#2-开放端口：&#34; class=&#34;headerlink&#34; title=&#34;2. 开放端口：&#34;&gt;&lt;/a&gt;2. 开放端口：&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/logs$ sudo apt-get install iptables&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/logs$ sudo ln -s /usr/sbin/iptables /usr/bin/iptables  //建立软连接&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/logs$ sudo iptables -I INPUT -p tcp --dport 81 -j ACCEPT  //开放81端口&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;持久化规则：这里我们需要在安装一下工具来帮我们实现，这里我们使用 &lt;code&gt;iptables-persistent&lt;/code&gt;&lt;br&gt;安装&lt;code&gt;iptables-persistent&lt;/code&gt;&lt;br&gt;  &lt;code&gt;yk@yk-pc:/etc/nginx/logs$ sudo apt-get install iptables-persistent&lt;/code&gt;&lt;br&gt;持久化规则&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/logs$ sudo netfilter-persistent save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/logs$ sudo netfilter-persistent reload&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;完成上述操作就可以永久打开我们需要的端口了&lt;/p&gt;
&lt;h3 id=&#34;3-关于权限问题：&#34;&gt;&lt;a href=&#34;#3-关于权限问题：&#34; class=&#34;headerlink&#34; title=&#34;3. 关于权限问题：&#34;&gt;&lt;/a&gt;3. 关于权限问题：&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt; yk@yk-pc:/etc/nginx/conf$ sudo vim nginx.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; [sudo] yk 的密码：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;#user  nobody;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注释掉&lt;code&gt;user&lt;/code&gt;，改为&lt;br&gt;&lt;code&gt;user  nginx;&lt;/code&gt;&lt;br&gt;重新加载出现：错误提示如下：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/conf$ sudo nginx -s reload&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;nginx: [emerg] getpwnam(&amp;quot;nginx&amp;quot;) failed in /etc/nginx/conf/nginx.conf:2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/conf$ sudo nginx -s closed&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;nginx: invalid option: &amp;quot;-s closed&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/conf$ sudo nginx -s stop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;nginx: [emerg] getpwnam(&amp;quot;nginx&amp;quot;) failed in /etc/nginx/conf/nginx.conf:2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;&lt;strong&gt;解决办法：&lt;/strong&gt;&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/conf$ sudo useradd -s /sbin/nologin -M  nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;useradd：用户“nginx”已存在&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/conf$ id nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;uid=117(nginx) gid=125(nginx) 组=125(nginx)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/conf$ systemctl start nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/etc/nginx/conf$  sudo nginx -s reload&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;4-make-upgrade-平滑升级&#34;&gt;&lt;a href=&#34;#4-make-upgrade-平滑升级&#34; class=&#34;headerlink&#34; title=&#34;4. make upgrade 平滑升级&#34;&gt;&lt;/a&gt;4. &lt;code&gt;make upgrade&lt;/code&gt; 平滑升级&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/sbin/mount.davfs: mounting failed; the server does not support WebDAV&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;原因是&lt;code&gt;mount.davfs&lt;/code&gt;命令在挂载时和 &lt;code&gt;WebDAV&lt;/code&gt; 服务器建立连接，并通过 &lt;code&gt;libneon&lt;/code&gt;库的 &lt;code&gt;ne_options&lt;/code&gt; 函数发送 &lt;code&gt;HTTP OPTIONS&lt;/code&gt; 请求获取 &lt;code&gt;WebDAV&lt;/code&gt; 服务器能力，虽然返回成功但判断坚果云 &lt;code&gt;WebDAV&lt;/code&gt; 服务器不支持 &lt;code&gt;Class 1 WebDAV&lt;/code&gt;，因此直接报错挂载失败。&lt;br&gt;看到这里解决办法也就简单了，&lt;code&gt;davfs2&lt;/code&gt; 提供了通过配置文件禁用 &lt;code&gt;WebDAV&lt;/code&gt;头检测的功能，&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;直接修改 /etc/davfs2/davfs2.conf 配置文件解注释并改为：ignore_dav_header 1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;参考：&#34;&gt;&lt;a href=&#34;#参考：&#34; class=&#34;headerlink&#34; title=&#34;参考：&#34;&gt;&lt;/a&gt;参考：&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;a href=&#34;http://www.v5b7.com/webserver/nginx/nginx_webdav.html&#34;&gt;nginx配置webdav：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.cnblogs.com/catlee/p/10290497.html&#34;&gt;源码编译安装nginx详细步骤：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://xieshaohu.wordpress.com/2019/07/12/nginx%E7%BC%96%E8%AF%91%E5%AE%89%E8%A3%85webdav%E6%A8%A1%E5%9D%97/&#34;&gt;nginx编译安装webdav模块：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://blog.ghostry.cn/server/889.html&#34;&gt;debian下为Nginx添加webdav:&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://blog.csdn.net/u013401853/article/details/113094734&#34;&gt;davfs挂载与使用缺陷：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.moerats.com/archives/317/&#34;&gt;Linux通过安装davfs2来挂载webdav网盘：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.cnblogs.com/Dev0ps/p/12000221.html&#34;&gt;Nginx服务加到systemctl:&lt;/a&gt;&lt;/li&gt;
&lt;/ol&gt;

 &lt;h1 id=&#34;写在前面&#34;&gt;&lt;a href=&#34;#写在前面&#34; class=&#34;headerlink&#34; title=&#34;写在前面&#34;&gt;&lt;/a&gt;写在前面&lt;/h1&gt;&lt;p&gt;&lt;a href=&#34;https://www.youtube-dl.org/&#34;&gt;youtube-dl官网：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/ytdl-org/youtube-dl/releases&#34;&gt;youtube-dl最新发布版本下载地址：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/aria2/aria2&#34;&gt;aria2项目：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/aria2/aria2&#34;&gt;aria2最新发布版本下载地址：&lt;/a&gt;  &lt;/p&gt;
&lt;h1 id=&#34;1、基本用法&#34;&gt;&lt;a href=&#34;#1、基本用法&#34; class=&#34;headerlink&#34; title=&#34;1、基本用法&#34;&gt;&lt;/a&gt;1、基本用法&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl &lt;span class=&#34;string&#34;&gt;&amp;quot;视频文件网络路径&amp;quot;&lt;/span&gt;  --external-downloader aria2c --external-downloader-args &lt;span class=&#34;string&#34;&gt;&amp;quot;-x 16 -k 1M&amp;quot;&lt;/span&gt; -o f:/yz3.mp4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;参数说明：&lt;br&gt;&lt;code&gt;--external-downloader aria2c&lt;/code&gt; //调用外部下载工具&lt;br&gt;&lt;code&gt;--external-downloader-args&lt;/code&gt; //外部下载工具指定参数&lt;br&gt;&lt;code&gt;-x 16&lt;/code&gt; //启用aria2 16个线程，最多就支持16线程&lt;br&gt;&lt;code&gt;-k 1M&lt;/code&gt; //指定块的大小&lt;br&gt;代理&lt;br&gt;&lt;code&gt;--proxy &amp;quot;https://127.0.0.1:1080&amp;quot;&lt;/code&gt;&lt;br&gt;  //或者直接这样&lt;br&gt;  &lt;code&gt;--proxy 127.0.0.1:1080&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;2、下载视频列表&#34;&gt;&lt;a href=&#34;#2、下载视频列表&#34; class=&#34;headerlink&#34; title=&#34;2、下载视频列表&#34;&gt;&lt;/a&gt;2、下载视频列表&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl [playlist_url] //下载视频列表,这种方式下载的视频可能是mkv格式或者webm格式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -cit [playlist_url] //下载视频列表,这种方式下载的视频可能是mkv格式或者webm格式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --yes-playlist [url] //当链接为视频列表,则下载该列表视频,跟上面的一样,可能是mkv或者webm格式&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;3、下载字幕&#34;&gt;&lt;a href=&#34;#3、下载字幕&#34; class=&#34;headerlink&#34; title=&#34;3、下载字幕&#34;&gt;&lt;/a&gt;3、下载字幕&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --write-sub --skip-download [url] //下载单独的vtt字幕文件,而不会下载视频&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --write-sub --all-subs [url] //下载所有语言的字幕(如果有的话)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --write-auto-sub [url] //下载自动生成的字幕(YouTube only)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;4、查看视频所有类型-只看不下载&#34;&gt;&lt;a href=&#34;#4、查看视频所有类型-只看不下载&#34; class=&#34;headerlink&#34; title=&#34;4、查看视频所有类型,只看不下载&#34;&gt;&lt;/a&gt;4、查看视频所有类型,只看不下载&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -F &lt;span class=&#34;string&#34;&gt;&amp;quot;视频文件网络路径&amp;quot;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;5、下载指定质量的视频和音频并自动合并&#34;&gt;&lt;a href=&#34;#5、下载指定质量的视频和音频并自动合并&#34; class=&#34;headerlink&#34; title=&#34;5、下载指定质量的视频和音频并自动合并&#34;&gt;&lt;/a&gt;5、下载指定质量的视频和音频并自动合并&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -f [format code] [url]   //format code :视频+音频如：137+140&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;format code  extension  resolution note&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;249          webm       audio only tiny   67k , opus @ 50k (48000Hz), 9.10MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;250          webm       audio only tiny   86k , opus @ 70k (48000Hz), 11.77MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;li