\end{array}&lt;/script&gt;&lt;h2 id=&#34;8、流程图&#34;&gt;&lt;a href=&#34;#8、流程图&#34; class=&#34;headerlink&#34; title=&#34;8、流程图&#34;&gt;&lt;/a&gt;8、流程图&lt;/h2&gt;&lt;p&gt;&lt;strong&gt;需安装插件：&lt;code&gt;flowchart&lt;/code&gt;&lt;/strong&gt;&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm i hexo-filter-flowchart --save &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;在根目录：_config.yml加入&lt;code&gt;flowchart&lt;/code&gt;支持:&lt;br&gt;&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;flowchart:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  # raphael:   # optional, the source url of raphael.js&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  # flowchart: # optional, the source url of flowchart.js&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  options: # options used for &lt;span class=&#34;code&#34;&gt;`drawSVG`&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;1、官方例子：&lt;br&gt;&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;st=&amp;gt;start: Start|past:&amp;gt;http://www.google.com[blank]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;e=&amp;gt;end: End:&amp;gt;http://www.google.com&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;op1=&amp;gt;operation: My Operation|past&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;op2=&amp;gt;operation: Stuff|current&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sub1=&amp;gt;subroutine: My Subroutine|invalid&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cond=&amp;gt;condition: Yes&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;or No?|approved:&amp;gt;http://www.google.com&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c2=&amp;gt;condition: Good idea|rejected&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io=&amp;gt;inputoutput: catch something...|request&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;st-&amp;gt;op1(right)-&amp;gt;cond&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cond(yes, right)-&amp;gt;c2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cond(no)-&amp;gt;sub1(left)-&amp;gt;op1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c2(yes)-&amp;gt;io-&amp;gt;e&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;c2(no)-&amp;gt;op2-&amp;gt;e&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;div id=&#34;flowchart-0&#34; class=&#34;flow-chart&#34;&gt;&lt;/div&gt;


&lt;p&gt;2、演示&lt;br&gt;&lt;figure class=&#34;highlight markdown&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;st=&amp;gt;start: 开始节点&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;in=&amp;gt;inputoutput: 输入i&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;e=&amp;gt;end: 结束节点&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cond=&amp;gt;condition: i被2整除&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;out1=&amp;gt;inputoutput: 输出i是奇数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;out2=&amp;gt;inputoutput: 输出i是偶数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;st(right)-&amp;gt;in-&amp;gt;cond&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cond(yes,right)-&amp;gt;out2-&amp;gt;e&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;cond(no)-&amp;gt;out1-&amp;gt;e&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;div id=&#34;flowchart-1&#34; class=&#34;flow-chart&#34;&gt;&lt;/div&gt;



