st-&gt;in-&gt;cond
cond(yes,right)-&gt;out2-&gt;e
cond(no)-&gt;out1-&gt;e&lt;/textarea&gt;&lt;textarea id=&#34;flowchart-1-options&#34; style=&#34;display: none&#34;&gt;{&#34;scale&#34;:1,&#34;line-width&#34;:2,&#34;line-length&#34;:50,&#34;text-margin&#34;:10,&#34;font-size&#34;:12}&lt;/textarea&gt;&lt;script&gt;  var code = document.getElementById(&#34;flowchart-1-code&#34;).value;  var options = JSON.parse(decodeURIComponent(document.getElementById(&#34;flowchart-1-options&#34;).value));  var diagram = flowchart.parse(code);  diagram.drawSVG(&#34;flowchart-1&#34;, options);&lt;/script&gt;&lt;/p&gt;

 &lt;p&gt;&lt;img src=&#34;\pic\2020\12\最小二乘法的算术推导.png&#34; alt=&#34;最小二乘法的算术推导&#34;&gt;&lt;/p&gt;
&lt;p&gt;$\hat y=a+bx$&lt;/p&gt;
&lt;p&gt;$\begin{aligned} Q&amp;amp;=\displaystyle \sum^n_{i=1}{(y_i-\hat y)^2}\\\&lt;br&gt;&amp;amp;={(y_1-\hat y_1)^2}+{(y_2-\hat y_2)^2}+ \cdots +{(y_n-\hat y_n)^2} \end{aligned}$&lt;/p&gt;
&lt;p&gt;其中$\hat y$为回归方程，求$Q$最小时回归方程的系数a，b取值。&lt;/p&gt;
&lt;h2 id=&#34;具体推导如下：&#34;&gt;&lt;a href=&#34;#具体推导如下：&#34; class=&#34;headerlink&#34; title=&#34;具体推导如下：&#34;&gt;&lt;/a&gt;具体推导如下：&lt;/h2&gt;&lt;h2 id=&#34;一、预备公式&#34;&gt;&lt;a href=&#34;#一、预备公式&#34; class=&#34;headerlink&#34; title=&#34;一、预备公式&#34;&gt;&lt;/a&gt;&lt;strong&gt;一、预备公式&lt;/strong&gt;&lt;/h2&gt;&lt;h3 id=&#34;1-gt&#34;&gt;&lt;a href=&#34;#1-gt&#34; class=&#34;headerlink&#34; title=&#34;1&amp;gt;&#34;&gt;&lt;/a&gt;1&amp;gt;&lt;/h3&gt;&lt;p&gt;$\displaystyle \sum^n_{i=1}{(x_i-{\bar x})^2}=\displaystyle \sum^n_{i=1}{x_i^2-n{\bar x}^2}$,&lt;/p&gt;
&lt;p&gt;其中:$\bar x=\frac {x_1+x_2+\cdots +x_n}{n}$&lt;/p&gt;
&lt;h5 id=&#34;推导&#34;&gt;&lt;a href=&#34;#推导&#34; class=&#34;headerlink&#34; title=&#34;推导:&#34;&gt;&lt;/a&gt;&lt;strong&gt;推导:&lt;/strong&gt;&lt;/h5&gt;&lt;p&gt;$\begin{aligned} 左边&amp;amp;={(x_1-\bar x_1)^2}+{(x_2-\bar x_2)^2}+ \cdots +{(x_n-\bar x_n)^2}\\\&lt;br&gt;&amp;amp;=x_1^2+x_2^2+ \cdots +x_n^2-2\bar x·(x_1+x_2+ \cdots +x_n)+n\bar x^2\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}{x_i^2}-2\bar x·n·\bar x + n·\bar x^2\\\&lt;br&gt;&amp;amp;=\displaystyle\sum^n_{i=1}{x_i^2-n\bar x^2}=右边 \end{aligned}$&lt;/p&gt;
&lt;h3 id=&#34;2-gt&#34;&gt;&lt;a href=&#34;#2-gt&#34; class=&#34;headerlink&#34; title=&#34;2&amp;gt;&#34;&gt;&lt;/a&gt;2&amp;gt;&lt;/h3&gt;&lt;p&gt;$\displaystyle\sum^n_{i=1}{(x_i-\bar x)}{(y_i-\bar y)}=\displaystyle \sum^n_{i=1}{x_i}{y_i}-n\bar x\bar y$，&lt;/p&gt;
&lt;p&gt;其中:$\bar x=\frac {x_1+x_2+\cdots+x_n}{n},\bar y=\frac{y_1+y_2+\cdots + y_n}{n}$&lt;/p&gt;
&lt;h5 id=&#34;推导：&#34;&gt;&lt;a href=&#34;#推导：&#34; class=&#34;headerlink&#34; title=&#34;推导：&#34;&gt;&lt;/a&gt;&lt;strong&gt;推导：&lt;/strong&gt;&lt;/h5&gt;&lt;p&gt;$\begin{aligned} 左边&amp;amp;={(x_1-\bar x_1)}{(y_1-\bar y_1)}+{(x_2-\bar x_2)}{(y_2-\bar y_2)}+ \cdots +{(x_n-\bar x_n)}{(y_n-\bar y_n)}\\\&lt;br&gt;&amp;amp;=(x_1y_1+x_2y_2+\cdots+x_n·y_n)+n\bar x·\bar y-(y_1+y_2+\cdots+y_n)·\bar x-(x_1+x_2+\cdots+x_n)·\bar y\\\&lt;br&gt;&amp;amp;=\displaystyle\sum^ n_{i=1}{x_i}{y_i}+n\bar x·\bar y-n\bar y·\bar x-n\bar x\bar y\\\&lt;br&gt;&amp;amp;=\displaystyle\sum^n_{i=1}{x_i}{y_i}-n\bar x\bar y=右边 \end{aligned}$&lt;/p&gt;
&lt;h2 id=&#34;二、推导过程&#34;&gt;&lt;a href=&#34;#二、推导过程&#34; class=&#34;headerlink&#34; title=&#34;二、推导过程&#34;&gt;&lt;/a&gt;&lt;strong&gt;二、推导过程&lt;/strong&gt;&lt;/h2&gt;&lt;p&gt;$\begin{aligned} Q &amp;amp;=\displaystyle \sum^n_{i=1}{(y_i-\hat y)^2}\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}{[y_i-(a+bx_i)]}^2\\\&lt;br&gt;&amp;amp;=(y_1^2+y_2^2+ \cdots +y_n^2)+na^2+b^2(x_1^2 + x_2^2 + \cdots +x_n^2)+2a·b·(x_1+x_2+\cdots+x_n)-2a·(y_1+y_2+\cdots +y_n)-2b(x_1·y_1+x_2·y_2+\cdots +x_n·y_n)\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}y_i^2+na^2+b^2·\displaystyle \sum^n_{i=1}x_i^2+2ab·n·\bar x-2a·n·\bar y-2b·\displaystyle \sum^n_{i=1}x_iy_i\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}y_i^2-2b\displaystyle \sum^n_{i=1}x_iy_i+b^2·\displaystyle \sum^n_{i=1}x_i^2+na^2-n·2a·(\bar y-b\bar x)\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}y_i^2-2b\displaystyle \sum^n_{i=1}x_iy_i+b^2·\displaystyle \sum^n_{i=1}x_i^2+n[a-(\bar y-b\bar x)]^2-n[(\bar y-b\bar x)]^2\\\&lt;br&gt;&amp;amp;=n[(\bar y-b\bar x)]^2-n\bar y^2+2n·b·\bar x·\bar y-n·b^2·\bar x^2+b^2·\displaystyle \sum^n_{i=1}x_i^2-2b·\displaystyle \sum^n_{i=1}x_iy_i+\displaystyle \sum^n_{i=1}y_i^2\\\&lt;br&gt;&amp;amp;=n[(\bar y-b\bar x)]^2+b^2(\displaystyle \sum^n_{i=1}x_i^2-n·\bar x^2)+\displaystyle \sum^n_{i=1}y_i^2-n·\bar y^2-2b·(\displaystyle \sum^n_{i=1}x_iy_i-n·\bar x·\bar y)\\\&lt;br&gt;&amp;amp;=n[a-(\bar y-b\bar x)]^2+b^2{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}-2b·\displaystyle \sum^n_{i=1}{(x_i-\bar x)(y_i-\bar y)}+\displaystyle \sum^n_{i=1}y_i^2-n·\bar y^2\\\&lt;br&gt;&amp;amp;=n[a-(\bar y-b\bar x)]^2+{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}·\left [b^2-2b·\frac {\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)}{\displaystyle \sum^n_{i=1}{(x_i-\bar x)^2}}\right ] +\displaystyle \sum^n_{i=1}y_i-n·\bar y^2\\\&lt;br&gt;&amp;amp;=n[a-(\bar y-b\bar x)]^2+{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}·\left [b-\frac {\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)}{\displaystyle \sum^n_{i=1}{(x_i-\bar x)^2}}\right ]^2-\frac {\left [{\displaystyle \sum^n_{i=1}}(x_i-{\bar x})(y_i-\bar y)\right ]^2}{\displaystyle \sum^n_{i=1}{(x_i-\bar x)^2}}+ \displaystyle \sum^n_{i=1}y_i-n·\bar y^2 \end{aligned}$&lt;br&gt;因为：&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;\displaystyle \sum^n_{i=1}(x_i-\bar x)^2&lt;/script&gt;&lt;p&gt;和&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;\frac {[\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)]^2}{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}&lt;/script&gt;&lt;p&gt;及&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;\displaystyle \sum^n_{i=1}y_i-n·\bar y^2&lt;/script&gt;&lt;p&gt;为常数。&lt;/p&gt;
&lt;p&gt;所以:&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;Q_{min}=
\begin{cases}
a-(\bar y-b\bar x)=0\\\
b-\frac {\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)}{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}=0
\end{cases}
\Longrightarrow \begin{cases} a=\bar y-b\bar x\\\
b=\frac {\displaystyle \sum^n_{i=1}(x_iy_i-n·\bar x\bar y)}{\displaystyle \sum^n_{i=1}x_i^2-n·\bar x^2}
\end{cases}&lt;/script&gt;

 &lt;p&gt;代码如下：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#!/usr/bin/env python&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Date    : 2020-12-19 15:02:56&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Author  : KY (xxxxxx@g.com)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Link    : http://example.org&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Version : $Id$&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; os&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;rename&lt;/span&gt;():&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    name = &lt;span class=&#34;string&#34;&gt;&amp;quot;p&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    count = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    path = &lt;span class=&#34;string&#34;&gt;&amp;quot;F:\Pictures\Assets&amp;quot;&lt;/span&gt; &lt;span class=&#34;comment&#34;&gt;#文件所在路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    filelist = os.listdir(path) &lt;span class=&#34;comment&#34;&gt;#该文件夹下所有的文件（包括文件夹）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; files &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; filelist: &lt;span class=&#34;comment&#34;&gt;#遍历所有文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Olddir = os.path.join(path,files) &lt;span class=&#34;comment&#34;&gt;#原来的文件路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; os.path.isdir(Olddir): &lt;span class=&#34;comment&#34;&gt;#如果是文件夹就跳过&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;keyword&#34;&gt;continue&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        filename = os.path.splitext(files)[&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;] &lt;span class=&#34;comment&#34;&gt;#文件名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        filetype = os.path.splitext(files)[&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;] &lt;span class=&#34;comment&#34;&gt;#扩展名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Newdir = os.path.join(path,&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(name)+&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(count)+filetype) &lt;span class=&#34;comment&#34;&gt;#新文件路径&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        os.rename(Olddir,Newdir) &lt;span class=&#34;comment&#34;&gt;#重新命名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        count += &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rename()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最终效果如图： &lt;img src=&#34;/pic/2020/12/Python批量重命名.jpg&#34; alt=&#34;重命名&#34;&gt;&lt;/p&gt;

 &lt;p&gt;[TOC]  &lt;/p&gt;
&lt;p&gt;在debian10上配置Hexo+Github做个人博客  &lt;/p&gt;
&lt;h1 id=&#34;一、nvm安装git&#34;&gt;&lt;a href=&#34;#一、nvm安装git&#34; class=&#34;headerlink&#34; title=&#34;一、nvm安装git&#34;&gt;&lt;/a&gt;一、nvm安装git&lt;/h1&gt;&lt;h2 id=&#34;1、安装nvm&#34;&gt;&lt;a href=&#34;#1、安装nvm&#34; class=&#34;headerlink&#34; title=&#34;1、安装nvm&#34;&gt;&lt;/a&gt;1、安装nvm&lt;/h2&gt;&lt;p&gt;命令：&lt;br&gt;cURL:&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ curl https://raw.github.com/creationix/nvm/master/install.sh | sh&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;或者&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Wget:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ wget -qO- https://raw.github.com/creationix/nvm/master/install.sh | sh&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;&lt;code&gt;nvm&lt;/code&gt;安装成功后，但命令不可用(&lt;code&gt;command not found&lt;/code&gt;)  &lt;/p&gt;
&lt;p&gt;解决方案：&lt;br&gt;运行以下命令&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/.nvm$ sudo vim .bash_profile&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;输入以下内容：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;export&lt;/span&gt; NVM_DIR=&lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$HOME&lt;/span&gt;/.nvm&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ -s &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$NVM_DIR&lt;/span&gt;/nvm.sh&amp;quot;&lt;/span&gt; ] &amp;amp;&amp;amp; \. &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$NVM_DIR&lt;/span&gt;/nvm.sh&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;查看输入内容：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/.nvm$ cat .bash_profile&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;export&lt;/span&gt; NVM_DIR=&lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$HOME&lt;/span&gt;/.nvm&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[ -s &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$NVM_DIR&lt;/span&gt;/nvm.sh&amp;quot;&lt;/span&gt; ] &amp;amp;&amp;amp; \. &lt;span class=&#34;string&#34;&gt;&amp;quot;&lt;span class=&#34;variable&#34;&gt;$NVM_DIR&lt;/span&gt;/nvm.sh&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;执行环境变量&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/.nvm$ &lt;span class=&#34;built_in&#34;&gt;source&lt;/span&gt; .bash_profile&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;解决每次需要执行环境变量问题：&#34;&gt;&lt;a href=&#34;#解决每次需要执行环境变量问题：&#34; class=&#34;headerlink&#34; title=&#34;解决每次需要执行环境变量问题：&#34;&gt;&lt;/a&gt;解决每次需要执行环境变量问题：&lt;/h3&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ sudo vim .bashrc&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;添加： &lt;code&gt;source /home/yk/.nvm/.bash_profile&lt;/code&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/nvm-sh/nvm&#34;&gt;开源项目&lt;code&gt;nvm&lt;/code&gt;地址&lt;/a&gt;&lt;/p&gt;
&lt;h3 id=&#34;解决&#34;&gt;&lt;a href=&#34;#解决&#34; class=&#34;headerlink&#34; title=&#34;解决&#34;&gt;&lt;/a&gt;解决&lt;/h3&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm install -g hexo-cli&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;##/usr/bin/env: “node”: 没有那个文件或目录&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;用&lt;code&gt;ln -s&lt;/code&gt;命令设置一个软链接&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo ln -s /home/yk/.nvm/versions/node/v14.15.2/bin/node /usr/bin/node&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;其他常用命令：&#34;&gt;&lt;a href=&#34;#其他常用命令：&#34; class=&#34;headerlink&#34; title=&#34;其他常用命令：&#34;&gt;&lt;/a&gt;其他常用命令：&lt;/h3&gt;&lt;h4 id=&#34;（1）用n升级nodejs&#34;&gt;&lt;a href=&#34;#（1）用n升级nodejs&#34; class=&#34;headerlink&#34; title=&#34;（1）用n升级nodejs&#34;&gt;&lt;/a&gt;（1）用n升级nodejs&lt;/h4&gt;&lt;p&gt; 全局安装n&lt;br&gt;&lt;code&gt;$ npm install -g n&lt;/code&gt;&lt;br&gt; 升级到最新稳定版&lt;br&gt;&lt;code&gt;$ n stable&lt;/code&gt;&lt;br&gt; 升级到最新版&lt;br&gt;&lt;code&gt;$ n latest&lt;/code&gt;&lt;br&gt; 升级到定制版&lt;br&gt;&lt;code&gt;$ n v7.10.0&lt;/code&gt;&lt;br&gt; 切换使用版本&lt;br&gt;&lt;code&gt;$ n 7.10.0 (ENTER)&lt;/code&gt;&lt;br&gt; 删除制定版本&lt;br&gt;&lt;code&gt;$ n rm 7.10.0&lt;/code&gt;&lt;br&gt;用制定的版本执行脚本&lt;br&gt;&lt;code&gt;$ n use 7.10.0 some.js&lt;/code&gt;  &lt;/p&gt;
&lt;h4 id=&#34;（2）安装npm&#34;&gt;&lt;a href=&#34;#（2）安装npm&#34; class=&#34;headerlink&#34; title=&#34;（2）安装npm&#34;&gt;&lt;/a&gt;（2）安装npm&lt;/h4&gt;&lt;p&gt;查看npm当前版本&lt;br&gt;&lt;code&gt;npm -v&lt;/code&gt;&lt;br&gt;如果不是最新版本，运行指令&lt;br&gt;&lt;code&gt;npm install -g npm&lt;/code&gt;&lt;br&gt;如果想更新到指定版本，运行指令&lt;br&gt;&lt;code&gt;npm -g install npm@6.8.0&lt;/code&gt; &lt;/p&gt;
&lt;h2 id=&#34;2、安装git&#34;&gt;&lt;a href=&#34;#2、安装git&#34; class=&#34;headerlink&#34; title=&#34;2、安装git&#34;&gt;&lt;/a&gt;2、安装git&lt;/h2&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/.nvm$ nvm install --lts  &lt;span class=&#34;comment&#34;&gt;##长期支持版本&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;将Debian10.1中默认的node更改文件名：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mv /usr/bin/node /usr/bin/node10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;在&lt;code&gt;/etc/profile&lt;/code&gt;,添加新的&lt;code&gt;node&lt;/code&gt;路径 &lt;code&gt;/usr/local/bin&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;export PATH=$PATH:/usr/local/bin&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;二、安装Next主题并部署到github【含从wordpress中导出】&#34;&gt;&lt;a href=&#34;#二、安装Next主题并部署到github【含从wordpress中导出】&#34; class=&#34;headerlink&#34; title=&#34;二、安装Next主题并部署到github【含从wordpress中导出】&#34;&gt;&lt;/a&gt;二、安装&lt;code&gt;Next&lt;/code&gt;主题并部署到&lt;code&gt;github&lt;/code&gt;【含从&lt;code&gt;wordpress&lt;/code&gt;中导出】&lt;/h1&gt;&lt;h2 id=&#34;1、按照Github提示，创建SSH秘钥：&#34;&gt;&lt;a href=&#34;#1、按照Github提示，创建SSH秘钥：&#34; class=&#34;headerlink&#34; title=&#34;1、按照Github提示，创建SSH秘钥：&#34;&gt;&lt;/a&gt;1、按照Github提示，创建SSH秘钥：&lt;/h2&gt;&lt;p&gt;（1）命令：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ mkdir ~/.ssh&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ &lt;span class=&#34;built_in&#34;&gt;cd&lt;/span&gt; ~/.ssh&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/.ssh$ ssh-keygen -t rsa -C &lt;span class=&#34;string&#34;&gt;&amp;quot;邮箱地址&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Generating public/private rsa key pair.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Enter file &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;which&lt;/span&gt; to save the key (/home/用户名/.ssh/id_rsa): &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Enter passphrase (empty &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; no passphrase): &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Enter same passphrase again: &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Your identification has been saved &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; /home/用户名/.ssh/id_rsa.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Your public key has been saved &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; /home/用户名/.ssh/id_rsa.pub.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;The key fingerprint is:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;SHA256:0NY9YEJ+aCViuJzyv**juiZ8 邮箱地址&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;The key&lt;span class=&#34;string&#34;&gt;&amp;#x27;s randomart image is:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;+---[RSA 2048]----+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;|     .o.*o++.    |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;|    .. * B=o     |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;|  o. o      o    |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;| ..o+o *     .   |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;|   o*.o So .     |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;| . =.o. .        |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;|  * .... . .     |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;| oo.o..          |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;| .o=             |&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;+----[SHA256]-----+&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;yk@YK-PC:~/.ssh$ ls -a&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;.  ..  id_rsa  id_rsa.pub&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;yk@YK-PC:~/.ssh$ cat id_rsa.pub&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQDXoLe6b+9fvDT/L8hcz***************eh+GK4vVv+1dyv9 注册github的邮箱&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;（2）打开&lt;code&gt;https://github.com/settings/keys&lt;/code&gt;，点击&lt;code&gt;New SSH key&lt;/code&gt;新增 &lt;code&gt;SSH KEY&lt;/code&gt;，tittle&lt;code&gt;debian10&lt;/code&gt;内容如上&lt;br&gt;（3）配置git&lt;br&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ git config --global user.name &lt;span class=&#34;string&#34;&gt;&amp;quot;注册github的用户名&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ git config --global user.email &lt;span class=&#34;string&#34;&gt;&amp;quot;注册github的邮箱&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;其他命令&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ git config --list  查看git配置&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ ssh -T git@github.com 查看与git的连接&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[sudo] yk 的密码：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ssh: connect to host github.com port 22: Connection timed out&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;提示错误  &lt;/p&gt;
&lt;p&gt;解决方法：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/.ssh$ sudo vim config&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;输入以下内容：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Host github.com&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;User 注册github的邮箱&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Hostname ssh.github.com&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;PreferredAuthentications publickey&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;IdentityFile ~/.ssh/id_rsa&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Port 443&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;2、安装hexo&#34;&gt;&lt;a href=&#34;#2、安装hexo&#34; class=&#34;headerlink&#34; title=&#34;2、安装hexo&#34;&gt;&lt;/a&gt;2、安装hexo&lt;/h2&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~$ sudo npm install -g hexo-cli&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;npm WARN deprecated fsevents@2.1.3: Please update to v 2.2.x&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/usr/&lt;span class=&#34;built_in&#34;&gt;local&lt;/span&gt;/bin/hexo -&amp;gt; /usr/&lt;span class=&#34;built_in&#34;&gt;local&lt;/span&gt;/lib/node_modules/hexo-cli/bin/hexo&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;3、创建存放博客的文件夹&#34;&gt;&lt;a href=&#34;#3、创建存放博客的文件夹&#34; class=&#34;headerlink&#34; title=&#34;3、创建存放博客的文件夹&#34;&gt;&lt;/a&gt;3、创建存放博客的文件夹&lt;/h2&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web$ sudo mkdir gitblog&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web$ &lt;span class=&#34;built_in&#34;&gt;cd&lt;/span&gt; gitblog&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo hexo init   &lt;span class=&#34;comment&#34;&gt;##初始化hexo设置&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm install&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install urix&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install resolve-url&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;文件夹出现&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;├── _config.yml     #配置文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;├── package.json    #应用程序数据&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;├── scaffolds&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;├── source          #网站内容&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   ├── _drafts     #草稿&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   └── _posts      #文章&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;└── themes          #主题&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;4、安装Next主题&#34;&gt;&lt;a href=&#34;#4、安装Next主题&#34; class=&#34;headerlink&#34; title=&#34;4、安装Next主题&#34;&gt;&lt;/a&gt;4、安装&lt;code&gt;Next&lt;/code&gt;主题&lt;/h2&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo git &lt;span class=&#34;built_in&#34;&gt;clone&lt;/span&gt; https://github.com/theme-next/hexo-theme-next themes/next&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;code&gt;// yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm i hexo-renderer-multi-markdown-it --save --ignore-scripts&lt;/code&gt;  #安装必备插件,&lt;code&gt;--ignore-scripts&lt;/code&gt; 解决安装依赖失败问题,&lt;br&gt;//但是安装此插件会出现数学公式重复解析&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm i hexo-autoprefixer --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm i hexo-algoliasearch --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm i hexo-symbols-count-time --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm i hexo-feed --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm uninstall hexo-renderer-marked --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install hexo-renderer-kramed --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm uninstall hexo-math --save  //停止使用 hexo-math&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install hexo-renderer-mathjax --save  //然后安装 hexo-renderer-mathjax 包：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install hexo-generator-search --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install hexo-generator-searchdb --save  &lt;span class=&#34;comment&#34;&gt;# 本地搜索 #&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install hexo-tag-cloud@^2.1.* --save   &lt;span class=&#34;comment&#34;&gt;##标签云&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo npm install eslint --save  &lt;span class=&#34;comment&#34;&gt;##阅读时长依赖&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;5、开启标签云：&#34;&gt;&lt;a href=&#34;#5、开启标签云：&#34; class=&#34;headerlink&#34; title=&#34;5、开启标签云：&#34;&gt;&lt;/a&gt;5、开启标签云：&lt;/h2&gt;&lt;p&gt;&lt;code&gt;swig&lt;/code&gt; 用户 (&lt;code&gt;Next&lt;/code&gt;主题在列)&lt;/p&gt;
&lt;p&gt;在主题文件夹找到文件 &lt;code&gt;theme/next/layout/_macro/sidebar.swig&lt;/code&gt;, 然后添加如下代码：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% if site.tags.length &amp;gt; 1 %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;script type=&amp;quot;text/javascript&amp;quot; charset=&amp;quot;utf-8&amp;quot; src=&amp;quot;/js/tagcloud.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;script type=&amp;quot;text/javascript&amp;quot; charset=&amp;quot;utf-8&amp;quot; src=&amp;quot;/js/tagcanvas.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;div class=&amp;quot;widget-wrap&amp;quot;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;h3 class=&amp;quot;widget-title&amp;quot;&amp;gt;Tag Cloud&amp;lt;/h3&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;div id=&amp;quot;myCanvasContainer&amp;quot; class=&amp;quot;widget tagcloud&amp;quot;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;canvas width=&amp;quot;250&amp;quot; height=&amp;quot;250&amp;quot; id=&amp;quot;resCanvas&amp;quot; style=&amp;quot;width=100%&amp;quot;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&amp;#123; list_tags() &amp;#125;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;lt;/canvas&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;/div&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/div&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;% endif %&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;6、从-Wordpress-迁移（没有用wordpress建站可无须此步）&#34;&gt;&lt;a href=&#34;#6、从-Wordpress-迁移（没有用wordpress建站可无须此步）&#34; class=&#34;headerlink&#34; title=&#34;6、从 Wordpress 迁移（没有用wordpress建站可无须此步）&#34;&gt;&lt;/a&gt;6、从 &lt;code&gt;Wordpress&lt;/code&gt; 迁移（没有用&lt;code&gt;wordpress&lt;/code&gt;建站可无须此步）&lt;/h2&gt;&lt;p&gt;（1）首先安装 &lt;code&gt;hexo-migrator-wordpress&lt;/code&gt; 插件：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo npm install hexo-migrator-wordpress --save&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;登录&lt;code&gt;Wordpress&lt;/code&gt; 后台，在&lt;code&gt;工具&lt;/code&gt;-&lt;code&gt;导出&lt;/code&gt;中导出所有记录。&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ yk@YK-PC:~/www/html/php-web/gitblog$ sudo hexo migrate wordpress &amp;lt;&lt;span class=&#34;built_in&#34;&gt;source&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;&lt;code&gt;source&lt;/code&gt; 是 &lt;code&gt;Wordpress&lt;/code&gt; 导出文件的存放目录：&lt;code&gt;/media/yk/文档/BackUp/数据备份/Linux相关/Debian网站文章备份/lifeinpieces.WordPress.2020-12-16.xml&lt;/code&gt;。  &lt;/p&gt;
&lt;p&gt;文章导入到&lt;code&gt;_posts&lt;/code&gt; 目录中了！&lt;/p&gt;
&lt;h2 id=&#34;7、提交到github&#34;&gt;&lt;a href=&#34;#7、提交到github&#34; class=&#34;headerlink&#34; title=&#34;7、提交到github&#34;&gt;&lt;/a&gt;7、提交到github&lt;/h2&gt;&lt;p&gt;安装支持：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog/owenyk.github.io$ sudo npm install hexo-deployer-git --unsafe-perm&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;提交命令：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo hexo generate&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo hexo deploy&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;一些问题：&#34;&gt;&lt;a href=&#34;#一些问题：&#34; class=&#34;headerlink&#34; title=&#34;一些问题：&#34;&gt;&lt;/a&gt;一些问题：&lt;/h3&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$  git remote add origin git@github.com:&lt;span class=&#34;comment&#34;&gt;#####/#####.github.io.git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fatal: 不是一个 git 仓库（或者直至挂载点 / 的任何父目录）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;停止在文件系统边界（未设置 GIT_DISCOVERY_ACROSS_FILESYSTEM）&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;解决：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo git init&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;已初始化空的 Git 仓库于 /home/yk/www/html/php-web/gitblog/.git/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo git remote add origin git@github.com:&lt;span class=&#34;comment&#34;&gt;###/###.github.io.git&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo git remote -v&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;origin	git@github.com:&lt;span class=&#34;comment&#34;&gt;###/###.github.io.git (fetch)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;origin	git@github.com:&lt;span class=&#34;comment&#34;&gt;###/###.github.io.git (push)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;提示：&lt;code&gt;This version of npm is compatible with lockfileVersion@1, but package-lock.json was generated for lockfileVersion@0. I&amp;#39;ll try to do my best with it!&lt;/code&gt;&lt;br&gt;解决：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:~/www/gitblogs$ sudo rm -rf node_modules package-lock.json &amp;amp;&amp;amp; npm install&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;8、换机操作&#34;&gt;&lt;a href=&#34;#8、换机操作&#34; class=&#34;headerlink&#34; title=&#34;8、换机操作&#34;&gt;&lt;/a&gt;8、换机操作&lt;/h2&gt;&lt;h3 id=&#34;1-、在你的博客Repository中新建一个“hexo”分支，名字自定：&#34;&gt;&lt;a href=&#34;#1-、在你的博客Repository中新建一个“hexo”分支，名字自定：&#34; class=&#34;headerlink&#34; title=&#34;(1)、在你的博客Repository中新建一个“hexo”分支，名字自定：&#34;&gt;&lt;/a&gt;(1)、在你的博客Repository中新建一个“hexo”分支，名字自定：&lt;/h3&gt;&lt;h3 id=&#34;2-、然后在setting中设置默认分支为hexo，便于推送：&#34;&gt;&lt;a href=&#34;#2-、然后在setting中设置默认分支为hexo，便于推送：&#34; class=&#34;headerlink&#34; title=&#34;(2)、然后在setting中设置默认分支为hexo，便于推送：&#34;&gt;&lt;/a&gt;(2)、然后在setting中设置默认分支为hexo，便于推送：&lt;/h3&gt;&lt;h3 id=&#34;3、新建目录，在目录下运行命令：&#34;&gt;&lt;a href=&#34;#3、新建目录，在目录下运行命令：&#34; class=&#34;headerlink&#34; title=&#34;(3、新建目录，在目录下运行命令：&#34;&gt;&lt;/a&gt;(3、新建目录，在目录下运行命令：&lt;/h3&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog$ sudo git &lt;span class=&#34;built_in&#34;&gt;clone&lt;/span&gt; https://github.com/owenyk/owenyk.github.io.git&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;4-、把除了-git-文件夹外的所有文件都删掉（这些是编译后的网页文件）&#34;&gt;&lt;a href=&#34;#4-、把除了-git-文件夹外的所有文件都删掉（这些是编译后的网页文件）&#34; class=&#34;headerlink&#34; title=&#34;(4)、把除了.git 文件夹外的所有文件都删掉（这些是编译后的网页文件）&#34;&gt;&lt;/a&gt;(4)、把除了&lt;code&gt;.git&lt;/code&gt; 文件夹外的所有文件都删掉（这些是编译后的网页文件）&lt;/h3&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@YK-PC:~/www/html/php-web/gitblog/owenyk.github.io$ sudo rm -rf [^.]*&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;5-、把之前我们写的博客源文件全部复制过来，除了-deploy-git（编译后的文件目录）。&#34;&gt;&lt;a href=&#34;#5-、把之前我们写的博客源文件全部复制过来，除了-deploy-git（编译后的文件目录）。&#34; class=&#34;headerlink&#34; title=&#34;(5)、把之前我们写的博客源文件全部复制过来，除了.deploy_git（编译后的文件目录）。&#34;&gt;&lt;/a&gt;(5)、把之前我们写的博客源文件全部复制过来，除了&lt;code&gt;.deploy_git&lt;/code&gt;（编译后的文件目录）。&lt;/h3&gt;&lt;p&gt;其中，&lt;code&gt;.gitignore&lt;/code&gt;（设置不需要git的文件或目录）文件中中需要设置部分不需要上传的目录：&lt;br&gt;删除题中有一个&lt;code&gt;.git&lt;/code&gt;目录&lt;br&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sudo git commit –m &lt;span class=&#34;string&#34;&gt;&amp;#x27;add branch&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sudo git checkout -b hexo_backup --track origin / hexo_backup&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;9、数学公式显示不正常问题：&#34;&gt;&lt;a href=&#34;#9、数学公式显示不正常问题：&#34; class=&#34;headerlink&#34; title=&#34;9、数学公式显示不正常问题：&#34;&gt;&lt;/a&gt;9、数学公式显示不正常问题：&lt;/h2&gt;&lt;h3 id=&#34;第一步：-使用Kramed代替Marked&#34;&gt;&lt;a href=&#34;#第一步：-使用Kramed代替Marked&#34; class=&#34;headerlink&#34; title=&#34;第一步： 使用Kramed代替Marked&#34;&gt;&lt;/a&gt;第一步： 使用&lt;code&gt;Kramed&lt;/code&gt;代替&lt;code&gt;Marked&lt;/code&gt;&lt;/h3&gt;&lt;p&gt;&lt;code&gt;hexo&lt;/code&gt; 默认的渲染引擎是 &lt;code&gt;marked&lt;/code&gt;，但是 &lt;code&gt;marked&lt;/code&gt; 不支持 &lt;code&gt;mathjax&lt;/code&gt;。 &lt;code&gt;kramed&lt;/code&gt; 是在 &lt;code&gt;marked&lt;/code&gt; 的基础上进行修改。我们在工程目录下执行以下命令来安装 &lt;code&gt;kramed&lt;/code&gt;.&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm uninstall hexo-renderer-marked --save&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;npm install hexo-renderer-kramed --save&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;然后，更改&lt;code&gt;&amp;lt;your-project-dir&amp;gt;/node_modules/hexo-renderer-kramed/lib/renderer.js&lt;/code&gt;，更改：&lt;br&gt;&lt;figure class=&#34;highlight js&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Change inline math rule&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;formatText&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;text&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// Fit kramed&amp;#x27;s rule: $$ + \1 + $$&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; text.replace(&lt;span class=&#34;regexp&#34;&gt;/`\$(.*?)\$`/g&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;$$$$$1$$$$&amp;#x27;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;为：&lt;br&gt;&lt;figure class=&#34;highlight js&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Change inline math rule&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;formatText&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;text&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; text;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;第二步-停止使用-hexo-math&#34;&gt;&lt;a href=&#34;#第二步-停止使用-hexo-math&#34; class=&#34;headerlink&#34; title=&#34;第二步: 停止使用 hexo-math&#34;&gt;&lt;/a&gt;第二步: 停止使用 &lt;code&gt;hexo-math&lt;/code&gt;&lt;/h3&gt;&lt;p&gt;首先，如果你已经安装 &lt;code&gt;hexo-math&lt;/code&gt;, 请卸载它：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm uninstall hexo-math --save`&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;然后安装 &lt;code&gt;hexo-renderer-mathjax&lt;/code&gt; 包：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;npm install hexo-renderer-mathjax --save&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;第三步-更新-Mathjax-的-CDN-链接&#34;&gt;&lt;a href=&#34;#第三步-更新-Mathjax-的-CDN-链接&#34; class=&#34;headerlink&#34; title=&#34;第三步: 更新 Mathjax 的 CDN 链接&#34;&gt;&lt;/a&gt;第三步: 更新 &lt;code&gt;Mathjax&lt;/code&gt; 的 &lt;code&gt;CDN&lt;/code&gt; 链接&lt;/h3&gt;&lt;p&gt;首先，打开&lt;code&gt;&amp;lt;path-to-your-project&amp;gt;/node_modules/hexo-renderer-mathjax/mathjax.html&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;然后，把&lt;code&gt;&amp;lt;script&amp;gt;&lt;/code&gt;更改为：&lt;br&gt;&lt;code&gt;&amp;lt;script src=&amp;quot;https://cdnjs.cloudflare.com/ajax/libs/mathjax/2.7.1/MathJax.js?config=TeX-MML-AM_CHTML&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;第四步-更改默认转义规则&#34;&gt;&lt;a href=&#34;#第四步-更改默认转义规则&#34; class=&#34;headerlink&#34; title=&#34;第四步: 更改默认转义规则&#34;&gt;&lt;/a&gt;第四步: 更改默认转义规则&lt;/h3&gt;&lt;p&gt;因为 &lt;code&gt;hexo&lt;/code&gt; 默认的转义规则会将一些字符进行转义，比如 &lt;code&gt;_&lt;/code&gt;转为 &lt;code&gt;&amp;lt;em&amp;gt;&lt;/code&gt;, 所以我们需要对默认的规则进行修改.&lt;br&gt;首先， 打开&lt;code&gt;&amp;lt;path-to-your-project/node_modules/kramed/lib/rules、inline.js&lt;/code&gt;,&lt;/p&gt;
&lt;p&gt;然后，把:&lt;br&gt;&lt;figure class=&#34;highlight js&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;escape&lt;/span&gt;: &lt;span class=&#34;regexp&#34;&gt;/^\\([\\`*&amp;#123;&amp;#125;\[\]()#$+\-.!_&amp;gt;])/&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;更改为:&lt;br&gt;&lt;figure class=&#34;highlight js&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;escape&lt;/span&gt;: &lt;span class=&#34;regexp&#34;&gt;/^\\([`*\[\]()# +\-.!_&amp;gt;])/&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;``&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;``&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;把&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;``&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;`js&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;string&#34;&gt;em: /^\b_((?:__|[\s\S])+?)_\b|^\*((?:\*\*|[\s\S])+?)\*(?!\*)/,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;更改为:&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;em: /^\*((?:\*\*|[\s\S])+?)\*(?!\*)/,&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;第五步-开启mathjax&#34;&gt;&lt;a href=&#34;#第五步-开启mathjax&#34; class=&#34;headerlink&#34; title=&#34;第五步: 开启mathjax&#34;&gt;&lt;/a&gt;第五步: 开启&lt;code&gt;mathjax&lt;/code&gt;&lt;/h3&gt;&lt;p&gt;在主题&lt;code&gt;_config.yml&lt;/code&gt; 中开启 &lt;code&gt;Mathjax&lt;/code&gt;， 找到 &lt;code&gt;mathjax&lt;/code&gt; 字段添加如下代码：&lt;br&gt;&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;mathjax:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;enable:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;这一步可选，在博客中开启 &lt;code&gt;Mathjax&lt;/code&gt;，， 添加以下内容：&lt;br&gt;&lt;figure class=&#34;highlight yml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;---&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;title:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;Testing&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;Mathjax&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;Hexo&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;category:&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;Uncategorized&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;date:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;2017&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;/05/03&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;mathjax:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;---&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;通过以上步骤，我们就可以在 &lt;code&gt;hexo&lt;/code&gt; 中使用 &lt;code&gt;Mathjax&lt;/code&gt; 来书写数学公式。&lt;/p&gt;
&lt;h2 id=&#34;参考资料：&#34;&gt;&lt;a href=&#34;#参考资料：&#34; class=&#34;headerlink&#34; title=&#34;参考资料：&#34;&gt;&lt;/a&gt;参考资料：&lt;/h2&gt;&lt;p&gt;&lt;a href=&#34;https://www.jianshu.com/p/6a29f5243ab4&#34;&gt;换终端更新hexo博客：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://blog.csdn.net/nightwishh/article/details/99647545&#34;&gt;git报错ssh: connect to host github.com port 22: Connection timed out:&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://zhuanlan.zhihu.com/p/149575559&#34;&gt;Hexo博客建立标签云及效果展示:&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://blog.csdn.net/jomes_wang/article/details/111628334&#34;&gt;hexo博客本地搜索失效，一直转圈:&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://www.jianshu.com/p/e8d433a2c5b7&#34;&gt;如何在 hexo 中支持 Mathjax？：&lt;/a&gt;&lt;/p&gt;

 &lt;h2 id=&#34;【【【【千万注意配置文件中勿用中文标点符号】】】】&#34;&gt;&lt;a href=&#34;#【【【【千万注意配置文件中勿用中文标点符号】】】】&#34; class=&#34;headerlink&#34; title=&#34;【【【【千万注意配置文件中勿用中文标点符号】】】】&#34;&gt;&lt;/a&gt;&lt;strong&gt;【【【【千万注意配置文件中勿用中文标点符号】】】】&lt;/strong&gt;&lt;/h2&gt;&lt;p&gt;3211版本注册码：&lt;br&gt;&lt;code&gt;请自寻搜索&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;一、安装插件安装控制-键ctrl&#34;&gt;&lt;a href=&#34;#一、安装插件安装控制-键ctrl&#34; class=&#34;headerlink&#34; title=&#34;一、安装插件安装控制 键ctrl+`&#34;&gt;&lt;/a&gt;一、安装插件安装控制 键ctrl+`&lt;/h3&gt;&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; urllib.request,os,hashlib; h = &lt;span class=&#34;string&#34;&gt;&amp;#x27;6f4c264a24d933ce70df5dedcf1dcaee&amp;#x27;&lt;/span&gt; + &lt;span class=&#34;string&#34;&gt;&amp;#x27;ebe013ee18cced0ef93d5f746d80ef60&amp;#x27;&lt;/span&gt;; pf = &lt;span class=&#34;string&#34;&gt;&amp;#x27;Package Control.sublime-package&amp;#x27;&lt;/span&gt;; ipp = sublime.installed_packages_path(); urllib.request.install_opener( urllib.request.build_opener( urllib.request.ProxyHandler()) ); by = urllib.request.urlopen( &lt;span class=&#34;string&#34;&gt;&amp;#x27;http://packagecontrol.io/&amp;#x27;&lt;/span&gt; + pf.replace(&lt;span class=&#34;string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;%20&amp;#x27;&lt;/span&gt;)).read(); dh = hashlib.sha256(by).hexdigest(); &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Error validating download (got %s instead of %s), please try manual install&amp;#x27;&lt;/span&gt; % (dh, h)) &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; dh != h &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(os.path.join( ipp, pf), &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt; ).write(by)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;二、安装SublimeTmpl-模板插件&#34;&gt;&lt;a href=&#34;#二、安装SublimeTmpl-模板插件&#34; class=&#34;headerlink&#34; title=&#34;二、安装SublimeTmpl 模板插件&#34;&gt;&lt;/a&gt;二、安装SublimeTmpl 模板插件&lt;/h3&gt;&lt;ol&gt;
&lt;li&gt;ctrl+alt+h html5模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+j js模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+c css模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+p php模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+r ruby模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+shift+p python模板 &lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;三、sublimeSideBar插件&#34;&gt;&lt;a href=&#34;#三、sublimeSideBar插件&#34; class=&#34;headerlink&#34; title=&#34;三、sublimeSideBar插件&#34;&gt;&lt;/a&gt;三、sublimeSideBar插件&lt;/h3&gt;&lt;p&gt;sublime text 3 localhost 配置 &lt;/p&gt;
&lt;h4 id=&#34;1-安装侧边栏增强插件&#34;&gt;&lt;a href=&#34;#1-安装侧边栏增强插件&#34; class=&#34;headerlink&#34; title=&#34;1. 安装侧边栏增强插件&#34;&gt;&lt;/a&gt;1. 安装侧边栏增强插件&lt;/h4&gt;&lt;p&gt;在 Sublime Text 3 中，安装 &lt;code&gt;SideBarEnhancements&lt;/code&gt; 侧边栏增强插件。 &lt;/p&gt;
&lt;h4 id=&#34;2-配置SideBarEnhancements-插件&#34;&gt;&lt;a href=&#34;#2-配置SideBarEnhancements-插件&#34; class=&#34;headerlink&#34; title=&#34;2. 配置SideBarEnhancements 插件&#34;&gt;&lt;/a&gt;2. 配置&lt;code&gt;SideBarEnhancements&lt;/code&gt; 插件&lt;/h4&gt;&lt;p&gt;&lt;code&gt;SideBarEnhancements&lt;/code&gt; 插件安装完成后，首先为 &lt;code&gt;SideBarEnhancements&lt;/code&gt; 指定默认浏览器。【见4】&lt;/p&gt;
&lt;h4 id=&#34;3-配置php环境&#34;&gt;&lt;a href=&#34;#3-配置php环境&#34; class=&#34;headerlink&#34; title=&#34;3. 配置php环境&#34;&gt;&lt;/a&gt;3. 配置php环境&lt;/h4&gt;&lt;p&gt;工具—-系统编译—-新编译系统 替换内容为 【配置php环境】&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    cmd: [php, $file],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    file_regex: php$,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    selector: source.php&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;另存文件—文件夹默认—文件名 &lt;code&gt;php.sublime-build&lt;/code&gt; &lt;/p&gt;
&lt;h4 id=&#34;4-指定默认浏览器&#34;&gt;&lt;a href=&#34;#4-指定默认浏览器&#34; class=&#34;headerlink&#34; title=&#34;4. 指定默认浏览器&#34;&gt;&lt;/a&gt;4. 指定默认浏览器&lt;/h4&gt;&lt;p&gt;打开 &lt;code&gt;Preference --&amp;gt; Package Settings --&amp;gt; Side Bar --&amp;gt; Settings User-User&lt;/code&gt;&lt;br&gt;【如果在热键绑定 browser: chrome中设置，在此可以不设置，即省略此步】&lt;br&gt;//单浏览器预览本地服务器url&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  default_browser: chrome &lt;span class=&#34;comment&#34;&gt;//one of this list: firefox, aurora, chrome, canary, chromium, opera, safari&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//多浏览器预览本地服务器url&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;open_all_browsers: [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        firefox,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        firefox-developer-edition,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        chrome,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        opera,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        safari,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ie,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        edge&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;5-指定默认localhsot目录&#34;&gt;&lt;a href=&#34;#5-指定默认localhsot目录&#34; class=&#34;headerlink&#34; title=&#34;5. 指定默认localhsot目录&#34;&gt;&lt;/a&gt;5. 指定默认localhsot目录&lt;/h4&gt;&lt;p&gt;为 SideBarEnhancements 指定默认localhsot目录。 在侧边栏任意文档上点击鼠标右键，选择 &lt;code&gt;Project --&amp;gt; Edit Preview URLs&lt;/code&gt; 【多站点配置】【文件名&lt;code&gt;SideBarEnhancements.json&lt;/code&gt;】&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F:\\php:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_testing: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8090/,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_production: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8090/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F:\\WebSite:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_testing: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8081/,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_production: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8081/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F:/asp/siteserver_install:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_testing: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8080/,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_production: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8080/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;6、热键绑定&#34;&gt;&lt;a href=&#34;#6、热键绑定&#34; class=&#34;headerlink&#34; title=&#34;6、热键绑定&#34;&gt;&lt;/a&gt;6、热键绑定&lt;/h4&gt;&lt;p&gt;打开 &lt;code&gt;Preference&lt;/code&gt; —&amp;gt; &lt;code&gt;Package Settings&lt;/code&gt; —&amp;gt; &lt;code&gt;Side Bar&lt;/code&gt; —&amp;gt; &lt;code&gt;key Bindings-User&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/s