ass=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;75&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;76&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;77&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;78&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;79&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;81&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;82&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;83&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;84&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;85&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;86&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;87&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;88&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;89&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;90&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;91&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;92&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;93&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;94&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;95&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;96&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;97&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;98&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;99&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;101&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;102&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;103&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;104&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;105&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;106&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;107&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;108&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;109&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;110&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;111&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;112&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;113&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;114&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;115&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;116&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;117&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;118&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;119&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;120&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;121&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;122&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;123&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;124&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;125&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;126&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;127&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;128&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;129&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;130&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;131&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;132&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;133&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;134&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;135&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;136&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;137&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;138&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;139&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;140&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;141&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;142&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;143&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;144&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;145&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;146&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;147&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f1],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        caption: Python,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: repl_open,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: subprocess,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            encoding: utf8,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cmd: [python, -i, -u],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cwd: $file_path,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            syntax: Packages/Python/Python.tmLanguage,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            external_id: python,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            extend_env:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                PYTHONIOENCODING: utf&lt;span class=&#34;number&#34;&gt;-8&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f2],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        caption: Py2,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: repl_open,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: subprocess,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            encoding: utf8,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cmd: [py2, -i, -u],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cwd: $file_path,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            syntax: Packages/Python/Python.tmLanguage,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            external_id: python,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            extend_env:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                PYTHONIOENCODING: utf&lt;span class=&#34;number&#34;&gt;-8&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f3],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: repl_open,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        caption: Python - RUN current file,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        id: repl_python_run,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mnemonic: R,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: subprocess,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            encoding: utf8,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cmd: [python, -u, $file_basename],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cwd: $file_path,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            syntax: Packages/Python/Python.tmLanguage,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            external_id: python,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            extend_env:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                PYTHONIOENCODING: utf&lt;span class=&#34;number&#34;&gt;-8&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f4],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: repl_open,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        caption: Python - RUN current file,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        id: repl_python_run,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        mnemonic: R,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: subprocess,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            encoding: utf8,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cmd: [py2, -u, $file_basename],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            cwd: $file_path,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            syntax: Packages/Python/Python.tmLanguage,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            external_id: python,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            extend_env:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                PYTHONIOENCODING: utf&lt;span class=&#34;number&#34;&gt;-8&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//系统默认浏览器预览&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f5],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: side_bar_open_in_browser,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            paths: [],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: testing,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            browser:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//chrome&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f6],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: side_bar_open_in_browser,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            paths: [],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//application: C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: testing,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            browser: chrome,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//ie&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f7],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: side_bar_open_in_browser,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            paths: [],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;comment&#34;&gt;//application: C:/Program Files/Internet Explorer/iexplore.exe,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: testing,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            browser: ie,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//edge&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [f8],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: side_bar_open_in_browser,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        args:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            paths: [],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            type: testing,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            browser: edge&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//Firefox&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//     keys: [f8],&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//     command: side_bar_files_open_with,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//     args: &amp;#123; paths: [],&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//     application: E:\\Program Files\\Mozilla Firfox\\firfox.exe,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//     extensions: .*&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;//     &amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;comment&#34;&gt;// &amp;#125;,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        keys: [ctrl+shift+w],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        command: color_picker,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        context: [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            key: color_highlighter.color_picker&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;四、SublimeREPL&#34;&gt;&lt;a href=&#34;#四、SublimeREPL&#34; class=&#34;headerlink&#34; title=&#34;四、SublimeREPL&#34;&gt;&lt;/a&gt;四、SublimeREPL&lt;/h3&gt;&lt;p&gt;模板插件 为CTRL + B绑定python&lt;/p&gt;
&lt;p&gt;1、打开 &lt;code&gt;Preference&lt;/code&gt; —&amp;gt; &lt;code&gt;Package Settings&lt;/code&gt; —&amp;gt;&lt;code&gt;REPL user&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    default_extend_env:&amp;#123;PATH:&amp;#123;PATH&amp;#125;;&amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    show_transferred_text:&lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;命名并保存 如：&lt;code&gt;replPy.sublime-settings&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;2、打开 &lt;code&gt;Tools&lt;/code&gt; —&amp;gt; &lt;code&gt;Bulid System&lt;/code&gt; —&amp;gt;&lt;code&gt;New System&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;target:run_existing_window_command,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;id:repl_python_run,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file:config/python/Main.sublime-menu&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;命名并保存 如：&lt;code&gt;ReplPy.sublime-build&lt;/code&gt; &lt;/p&gt;
&lt;h3 id=&#34;五、Anaconda-python语法自动填充插件&#34;&gt;&lt;a href=&#34;#五、Anaconda-python语法自动填充插件&#34; class=&#34;headerlink&#34; title=&#34;五、Anaconda python语法自动填充插件&#34;&gt;&lt;/a&gt;五、Anaconda python语法自动填充插件&lt;/h3&gt;&lt;p&gt;打开 &lt;code&gt;Preference&lt;/code&gt; —&amp;gt; &lt;code&gt;Package Settings&lt;/code&gt; —&amp;gt;&lt;code&gt;Anaconda user&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    python_interpreter:E:/Program Files/Python3/python.exe,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    suppress_word_completions:&lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    suppress_explicit_completions:&lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    complete_parameters:&lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;,     &lt;span class=&#34;comment&#34;&gt;//解决自动填充参数过多&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    swallow_startup_errors: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;, &lt;span class=&#34;comment&#34;&gt;//解决启动错误&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    anaconda_linting: &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;, &lt;span class=&#34;comment&#34;&gt;//解决白框&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;其他插件&lt;br&gt;前端&lt;br&gt;极速生成html代码插件 &lt;code&gt;Emmet&lt;/code&gt;&lt;br&gt;代码自动补全插件     &lt;code&gt;SublimeCodeIntel&lt;/code&gt;&lt;br&gt;资源查看器插件       &lt;code&gt;PackageResourceViewer&lt;/code&gt;&lt;br&gt;可修改插件配置&lt;br&gt;【【【【千万注意勿用中文标点符号】】】】 &lt;/p&gt;
&lt;h3 id=&#34;六、IIS配置PHP环境&#34;&gt;&lt;a href=&#34;#六、IIS配置PHP环境&#34; class=&#34;headerlink&#34; title=&#34;六、IIS配置PHP环境&#34;&gt;&lt;/a&gt;六、IIS配置PHP环境&lt;/h3&gt;&lt;h4 id=&#34;一-安装配置PHP&#34;&gt;&lt;a href=&#34;#一-安装配置PHP&#34; class=&#34;headerlink&#34; title=&#34;(一)安装配置PHP&#34;&gt;&lt;/a&gt;(一)安装配置PHP&lt;/h4&gt;&lt;p&gt;1、首先到php官网上下载php&lt;a href=&#34;http://php.net/downloads.php&#34;&gt;Php官网链接&lt;/a&gt;,&lt;code&gt;windows download&lt;/code&gt; （版本根据自己的需要定)&lt;/p&gt;
&lt;p&gt;2、下载&lt;code&gt;php-7.3.6-nts-Win32-VC15-x86&lt;/code&gt;(根据情况自行选择32/64位) &lt;/p&gt;
&lt;p&gt;3、解压进入解压目录，找到&lt;code&gt;php.ini-development&lt;/code&gt;这个文件，可以直接改名为&lt;code&gt;php.ini&lt;/code&gt;文件,修改配置将需要配置的去掉前面的&lt;code&gt;;&lt;/code&gt;启用配置： 如： &lt;code&gt;; On windows: extension_dir = E:\\Program Files\\PHP\\php-7.3.6-nts-VC15\\ext&lt;/code&gt;（放置扩展的目录）&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;extension=odbc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=openssl&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=pdo_firebird&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=pdo_mysql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=pdo_oci&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=pdo_odbcs&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=pdo_pgsql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=pdo_sqlite&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=pgsql ;配置支持MSSQL&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;extension=php_sqlsrv_73_nts_x86 extension=php_sqlsrv_73_ts_x86 extension=php_pdo_sqlsrv_73_nts_x86 extension=php_pdo_sqlsrv_73_ts_x86&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最后不要忘了设置session文件的存储目录配置： 文件里的默认设置是：&lt;code&gt;; session.save_path=/tmp&lt;/code&gt; 目录要改一下，改成自己用来存放session文件的目录。 如:&lt;code&gt;session.save_path=F:\\tmp&lt;/code&gt;. 配置完后保存退出，还要设置一下“&lt;code&gt;F:\\tmp&lt;/code&gt;文件夹的权限，不然会提示错误。 &lt;code&gt;文件夹&lt;/code&gt;→&lt;code&gt;属性&lt;/code&gt;→&lt;code&gt;安全给IIS_IUSRS&lt;/code&gt;用户授权&lt;/p&gt;
&lt;h4 id=&#34;二-安装配置IIS&#34;&gt;&lt;a href=&#34;#二-安装配置IIS&#34; class=&#34;headerlink&#34; title=&#34;(二)安装配置IIS&#34;&gt;&lt;/a&gt;(二)安装配置IIS&lt;/h4&gt;&lt;p&gt;1、控制面板→程序→打开或关闭Windows功能→Internet信息服务 【确保勾选”&lt;code&gt;IIS管理控制台&lt;/code&gt;“和”&lt;code&gt;万维网服务&lt;/code&gt;“中的“&lt;code&gt;应用程序开发功能&lt;/code&gt;”→“&lt;code&gt;CGI&lt;/code&gt;”】&lt;/p&gt;
&lt;p&gt;2、配置PHP运行环境： 启动&lt;code&gt;IIS信息管理器&lt;/code&gt;→&lt;code&gt;处理程序映射&lt;/code&gt;→&lt;code&gt;添加模块映射&lt;/code&gt;→&lt;code&gt;请求路径&lt;/code&gt;：“&lt;code&gt;*.php&lt;/code&gt;”;模块：&lt;code&gt;FastCgiModule&lt;/code&gt;;&lt;/p&gt;
&lt;p&gt;可执行文件：解压的PHP目录下“&lt;code&gt;php-cgi.exe&lt;/code&gt;”;名称：“&lt;code&gt;PHP&lt;/code&gt;” &lt;/p&gt;
&lt;h3 id=&#34;七、PHP配置连接MSSQL扩展&#34;&gt;&lt;a href=&#34;#七、PHP配置连接MSSQL扩展&#34; class=&#34;headerlink&#34; title=&#34;七、PHP配置连接MSSQL扩展&#34;&gt;&lt;/a&gt;七、PHP配置连接MSSQL扩展&lt;/h3&gt;&lt;p&gt;1、下载SQL Server驱动4.0 &lt;a href=&#34;https://docs.microsoft.com/en-us/sql/connect/php/download-drivers-php-sql-server?view=sql-server-2017&#34;&gt;SQL Server驱动4.0下载地址&lt;/a&gt; 放到php安装目录下的ext目录下 并给php.ini添加配置 （在前面第五部分）&lt;/p&gt;
&lt;p&gt;2、安装ODBC驱动11 &lt;a href=&#34;https://www.microsoft.com/en-us/download/details.aspx?id=36434&#34;&gt;ODBC驱动下载地址&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;3、测试数据库连接&lt;/p&gt;
&lt;p&gt;①sqlsrv_connect&lt;br&gt;&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$serverName&lt;/span&gt; = localhost, &lt;span class=&#34;number&#34;&gt;1433&lt;/span&gt;; &lt;span class=&#34;comment&#34;&gt;//serverName\instanceName, portNumber (default is 1433)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$connectionInfo&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;array&lt;/span&gt;( Database=&amp;gt;PHP, UID=&amp;gt;sa, PWD=&amp;gt;xxxxx);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$conn&lt;/span&gt; = sqlsrv_connect( &lt;span class=&#34;variable&#34;&gt;$serverName&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$connectionInfo&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;( &lt;span class=&#34;variable&#34;&gt;$conn&lt;/span&gt; ) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; 连接成功.&amp;lt;br /&amp;gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; 连接出现错误.&amp;lt;br /&amp;gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;( print_r( sqlsrv_errors(), &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;?&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;②PDO连接&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$servername&lt;/span&gt; = localhost;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$username&lt;/span&gt; = sa;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$password&lt;/span&gt; = XXXXXX;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable&#34;&gt;$conn&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; PDO(sqlsrv:Server=&lt;span class=&#34;variable&#34;&gt;$servername&lt;/span&gt;;, &lt;span class=&#34;variable&#34;&gt;$username&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$password&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; PDO连接方式连接成功; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt;(PDOException &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;连接失败：&amp;#x27;&lt;/span&gt;. &lt;span class=&#34;variable&#34;&gt;$e&lt;/span&gt;-&amp;gt;getMessage();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;//③、odbc_connect 测试连接access&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;meta&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// Microsoft SQL Server using the SQL Native Client 10.0 ODBC Driver - allows connection to SQL 7, 2000, 2005 and 2008&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// $db=f:/asp/siteserver_install/gdjy/students.mdb;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$mdbFilename&lt;/span&gt;=f:/asp/siteserver_install/gdjy/students.mdb;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$username&lt;/span&gt; = oooooo;  &lt;span class=&#34;comment&#34;&gt;//用户名&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$password&lt;/span&gt; = xxxxx;   &lt;span class=&#34;comment&#34;&gt;//密码&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$connection&lt;/span&gt; = odbc_connect(Driver=&amp;#123;Microsoft Access Driver (*.mdb)&amp;#125;;Dbq=&lt;span class=&#34;variable&#34;&gt;$mdbFilename&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$username&lt;/span&gt;, &lt;span class=&#34;variable&#34;&gt;$password&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// try &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//  $connection = odbc_connect(Driver=&amp;#123;Microsoft Access Driver (*.mdb)&amp;#125;;Dbq=$mdbFilename, $username, $password);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//  echo 连接成功;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// &amp;#125;catch(odbc_connect $e)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//     echo &amp;#x27;连接失败：&amp;#x27;. $e-&amp;gt;getMessage();&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// &amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (&lt;span class=&#34;variable&#34;&gt;$connection&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; 连接成功.;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;die&lt;/span&gt;(Connection could not be established.);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;asp查询页面&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;response.expires=-1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;user = trim(request.querystring(&amp;quot;name&amp;quot;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if user = &amp;quot;&amp;quot; then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    response.write escape(&amp;quot;&amp;lt;font style=&amp;quot;&amp;quot;color:red&amp;quot;&amp;quot;&amp;gt;姓名或学员ID不能为空格！&amp;lt;/font&amp;gt;&amp;quot;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    response.End()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;end if&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sql = &amp;quot;select * from students where usrname =&amp;#x27;&amp;quot;&amp;amp;user&amp;amp;&amp;quot;&amp;#x27; or usr_ID=&amp;#x27;&amp;quot;&amp;amp;user&amp;amp;&amp;quot;&amp;#x27;&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;sql = sql &amp;amp;&amp;quot;&amp;#x27;&amp;quot;&amp;amp; request.querystring(&amp;quot;name&amp;quot;) &amp;amp;&amp;quot;&amp;#x27;&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x27;使用sql对conn进行查询，后面的参数代表我要完全操作这个数据库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Set rs = Server.CreateObject( &amp;quot;ADODB.Recordset&amp;quot; )&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rs.open sql,conn,1,1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;js处理页面&lt;/p&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;createAjax&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;span class=&#34;comment&#34;&gt;//该函数将返回XMLHTTP对象实例&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; _xmlhttp; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    _xmlhttp=&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; ActiveXObject(&lt;span class=&#34;string&#34;&gt;&amp;quot;Microsoft.XMLHTTP&amp;quot;&lt;/span&gt;); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (e) &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt; &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    _xmlhttp=&lt;span class=&#34;keyword&#34;&gt;new&lt;/span&gt; XMLHttpRequest(); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;catch&lt;/span&gt; (e) &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    _xmlhttp=&lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; _xmlhttp; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;checkname&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;name&lt;/span&gt;) &lt;/span&gt;&amp;#123; &lt;span class=&#34;comment&#34;&gt;//该函数用来获取数据 用户名//alert(idname)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; xmlhttp1=createAjax();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (xmlhttp1) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; span=&lt;span class=&#34;built_in&#34;&gt;document&lt;/span&gt;.getElementById(&lt;span class=&#34;string&#34;&gt;&amp;#x27;check&amp;#x27;&lt;/span&gt;); &lt;span class=&#34;comment&#34;&gt;// 获取显示节点  &lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    xmlhttp1.open(&lt;span class=&#34;string&#34;&gt;&amp;#x27;get&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;checkname.asp?name=&amp;#x27;&lt;/span&gt;+name+&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;amp;n=&amp;#x27;&lt;/span&gt;+&lt;span class=&#34;built_in&#34;&gt;Math&lt;/span&gt;.random(),&lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;);   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    xmlhttp1.onreadystatechange=&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (xmlhttp1.readyState==&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt; &amp;amp;&amp;amp; xmlhttp1.status==&lt;span class=&#34;number&#34;&gt;200&lt;/span&gt;)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        span.innerHTML=&lt;span class=&#34;built_in&#34;&gt;unescape&lt;/span&gt;(xmlhttp1.responseText);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &amp;#125;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        span.innerHTML=&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;span style=&amp;quot;color:red&amp;quot;&amp;gt;xmlhttp对象正在初始化......&amp;lt;/span&amp;gt;&amp;#x27;&lt;/span&gt;;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    xmlhttp1.send(&lt;span class=&#34;literal&#34;&gt;null&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;一、Dell的BIOS设置&#34;&gt;&lt;a href=&#34;#一、Dell的BIOS设置&#34; class=&#34;headerlink&#34; title=&#34;一、Dell的BIOS设置&#34;&gt;&lt;/a&gt;一、Dell的BIOS设置&lt;/h2&gt;&lt;h3 id=&#34;1、电脑开机，按F2，进入BIOS&#34;&gt;&lt;a href=&#34;#1、电脑开机，按F2，进入BIOS&#34; class=&#34;headerlink&#34; title=&#34;1、电脑开机，按F2，进入BIOS&#34;&gt;&lt;/a&gt;1、电脑开机，按&lt;code&gt;F2&lt;/code&gt;，进入BIOS&lt;/h3&gt;&lt;h3 id=&#34;2、选择Secure-Boot-Enable-关闭Disabled&#34;&gt;&lt;a href=&#34;#2、选择Secure-Boot-Enable-关闭Disabled&#34; class=&#34;headerlink&#34; title=&#34;2、选择Secure Boot Enable,关闭Disabled&#34;&gt;&lt;/a&gt;2、选择&lt;code&gt;Secure Boot Enable&lt;/code&gt;,关闭&lt;code&gt;Disabled&lt;/code&gt;&lt;/h3&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8vuVrHb8AisLyeLjAqBKCK.KnVU6UfCNMUduYVQJeHQjvn50E9SjkLYWSNSustEtTA!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0211501698&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;Secure Boot Enable&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;3、设置硬盘模式为AHCI&#34;&gt;&lt;a href=&#34;#3、设置硬盘模式为AHCI&#34; class=&#34;headerlink&#34; title=&#34;3、设置硬盘模式为AHCI&#34;&gt;&lt;/a&gt;3、设置硬盘模式为&lt;code&gt;AHCI&lt;/code&gt;&lt;/h3&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8q5JqDJRaxmMPCYpJGjoHhzrp1PF*hWQcACMqjIqqq4CJZsQ1YNOYGjleztVzYBOwQ!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=049455234&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;SATA Operation&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;4、修改BIOS引导顺序&#34;&gt;&lt;a href=&#34;#4、修改BIOS引导顺序&#34; class=&#34;headerlink&#34; title=&#34;4、修改BIOS引导顺序&#34;&gt;&lt;/a&gt;4、修改&lt;code&gt;BIOS&lt;/code&gt;引导顺序&lt;/h3&gt;&lt;p&gt; &lt;code&gt;Boot List Option&lt;/code&gt;选择UEFI，&lt;code&gt;Boot Sequence&lt;/code&gt;添加装好Ventoy的U盘。&lt;/p&gt;
&lt;p&gt; &lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8nqhZkU.rjx9uX.D7RSoD*5WpPyVTQh1nAkrb6WKgkwm27KbfvTmrDBtQJBunq92VQ!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=074209938&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;Boot List Option&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;二、Ventoy装系统&#34;&gt;&lt;a href=&#34;#二、Ventoy装系统&#34; class=&#34;headerlink&#34; title=&#34;二、Ventoy装系统&#34;&gt;&lt;/a&gt;二、Ventoy装系统&lt;/h2&gt;&lt;h3 id=&#34;1、开机按F12-进入引导界面&#34;&gt;&lt;a href=&#34;#1、开机按F12-进入引导界面&#34; class=&#34;headerlink&#34; title=&#34;1、开机按F12,进入引导界面&#34;&gt;&lt;/a&gt;1、开机按&lt;code&gt;F12&lt;/code&gt;,进入引导界面&lt;/h3&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8gvcZJhdaXo7zzl*y.Rj2nv5NeOj.dnnWZt8cGlXP0OWXuQUnNr*RCB5R59FKOOlkw!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0206014546&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;Boot List&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;2、安装win10&#34;&gt;&lt;a href=&#34;#2、安装win10&#34; class=&#34;headerlink&#34; title=&#34;2、安装win10&#34;&gt;&lt;/a&gt;2、安装win10&lt;/h3&gt;&lt;h4 id=&#34;1-gt-进入Ventoy界面，选择win10系统ISO文件-安装win10&#34;&gt;&lt;a href=&#34;#1-gt-进入Ventoy界面，选择win10系统ISO文件-安装win10&#34; class=&#34;headerlink&#34; title=&#34;1&amp;gt; 进入Ventoy界面，选择win10系统ISO文件,安装win10&#34;&gt;&lt;/a&gt;1&amp;gt; 进入Ventoy界面，选择win10系统ISO文件,安装win10&lt;/h4&gt;&lt;p&gt;win10系统ISO文件下载方法：&lt;/p&gt;
&lt;p&gt;进入&lt;a href=&#34;https://www.microsoft.com/zh-cn/software-download/windows10ISO&#34;&gt;win10系统ISO地址&lt;/a&gt;,&lt;code&gt;开启浏览器调试&lt;/code&gt;，&lt;code&gt;刷新&lt;/code&gt;，即可出现ISO文件选择下载界面,关掉调试，选择需要的ISO文件下载即可。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;\pic\2020\12\win10系统ISO.png&#34; alt=&#34;win10系统ISO&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8gghMFD.tJ2tFrmHjBiRaQixkRHd4DdL8rgOaqb*W8Om82l.7KfJs6Rstr.wE*fj4g!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0222155314&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;win10系统ISO文件&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;2-gt-32或者64系统选择&#34;&gt;&lt;a href=&#34;#2-gt-32或者64系统选择&#34; class=&#34;headerlink&#34; title=&#34;2&amp;gt; 32或者64系统选择&#34;&gt;&lt;/a&gt;2&amp;gt; 32或者64系统选择&lt;/h4&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8hNUrg6v9JUKjsrt4gJjaw1gvhMu0DySB5pdnXJvw8PQjxHmk*vmlELNhN6SFrAxWw!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0224711266&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;32或者64系统&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;3-gt-加载程序&#34;&gt;&lt;a href=&#34;#3-gt-加载程序&#34; class=&#34;headerlink&#34; title=&#34;3&amp;gt; 加载程序&#34;&gt;&lt;/a&gt;3&amp;gt; 加载程序&lt;/h4&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8gbIeAwdhyU6kdd6.uqbu6RUDdQ4xytu0*ShBZ6AMHuRRurBX9X6gSpdmwjlr8ZVEA!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0265058578&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;32或者64系统&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;4-gt-程序安装&#34;&gt;&lt;a href=&#34;#4-gt-程序安装&#34; class=&#34;headerlink&#34; title=&#34;4&amp;gt; 程序安装&#34;&gt;&lt;/a&gt;4&amp;gt; 程序安装&lt;/h4&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8hL.UVWAhiaikAhsH52KJQxnmIdrsoRryicUXXXOn*kVxzm8LREqUU5gswEhw4p*kA!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0130022610&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;32或者64系统&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;3、安装win7&#34;&gt;&lt;a href=&#34;#3、安装win7&#34; class=&#34;headerlink&#34; title=&#34;3、安装win7&#34;&gt;&lt;/a&gt;3、安装win7&lt;/h3&gt;&lt;p&gt;【注意：32位启动不支持UEFI】&lt;/p&gt;
&lt;h4 id=&#34;1-gt-需配合wepe安装微pe地址，&#34;&gt;&lt;a href=&#34;#1-gt-需配合wepe安装微pe地址，&#34; class=&#34;headerlink&#34; title=&#34;1&amp;gt; 需配合wepe安装微pe地址，&#34;&gt;&lt;/a&gt;1&amp;gt; 需配合wepe安装&lt;a href=&#34;http://www.wepe.com.cn/download.html&#34;&gt;微pe地址&lt;/a&gt;，&lt;/h4&gt;&lt;h4 id=&#34;2-gt-将工具箱制作成IOS镜像制作方法地址&#34;&gt;&lt;a href=&#34;#2-gt-将工具箱制作成IOS镜像制作方法地址&#34; class=&#34;headerlink&#34; title=&#34;2&amp;gt; 将工具箱制作成IOS镜像制作方法地址&#34;&gt;&lt;/a&gt;2&amp;gt; 将工具箱制作成IOS镜像&lt;a href=&#34;http://www.wepe.com.cn/ubook/installwepe.html&#34;&gt;制作方法地址&lt;/a&gt;&lt;/h4&gt;&lt;p&gt;【在下面制作中注意选择右下角&lt;code&gt;**光盘**&lt;/code&gt;图标】&lt;br&gt;&lt;img src=&#34;http://www.wepe.com.cn/ubook/assets/img/PE2.d658a63d.png&#34; alt=&#34;Wepe工具箱安装到U盘&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;3-gt-放进装好Ventoy的U盘，选择Wepe-64-v2-1-iso-根据前面安装工具箱版本不一样名称也会不一样&#34;&gt;&lt;a href=&#34;#3-gt-放进装好Ventoy的U盘，选择Wepe-64-v2-1-iso-根据前面安装工具箱版本不一样名称也会不一样&#34; class=&#34;headerlink&#34; title=&#34;3&amp;gt; 放进装好Ventoy的U盘，选择Wepe_64_v2.1.iso(根据前面安装工具箱版本不一样名称也会不一样)&#34;&gt;&lt;/a&gt;3&amp;gt; 放进装好&lt;code&gt;Ventoy&lt;/code&gt;的U盘，选择&lt;code&gt;Wepe_64_v2.1.iso&lt;/code&gt;(根据前面安装工具箱版本不一样名称也会不一样)&lt;/h4&gt;&lt;h4 id=&#34;4-gt-进入桌面，选择DiskGenius格式需要安装的影片盘符，退出&#34;&gt;&lt;a href=&#34;#4-gt-进入桌面，选择DiskGenius格式需要安装的影片盘符，退出&#34; class=&#34;headerlink&#34; title=&#34;4&amp;gt; 进入桌面，选择DiskGenius格式需要安装的影片盘符，退出&#34;&gt;&lt;/a&gt;4&amp;gt; 进入桌面，选择&lt;code&gt;DiskGenius&lt;/code&gt;格式需要安装的影片盘符，退出&lt;/h4&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8m.SS64jkSwYiDNdIh5PYDv3lDI0H9nyONLgFhaNyPFii7Z.D5FRjvN15Ko3DUd3cw!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0224512754&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;Wepe界面&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8jAzlgT5ednp7ZHcGhpK23B0xRSz3Lb1RyDzjDYF*9gHFL.u1kl5v2.JqVuTrsGHYQ!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0268258098&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;DiskGenius&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;5-gt-选择WinNTSetp安装器进行安装&#34;&gt;&lt;a href=&#34;#5-gt-选择WinNTSetp安装器进行安装&#34; class=&#34;headerlink&#34; title=&#34;5&amp;gt; 选择WinNTSetp安装器进行安装&#34;&gt;&lt;/a&gt;5&amp;gt; 选择&lt;code&gt;WinNTSetp&lt;/code&gt;安装器进行安装&lt;/h4&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8gO5ou.Xocae1wB*mnzfYeQO*Xc7VdY7oDlqmnm2Cw43eBTl5mklUdSxA4951FdtHw!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0215562530&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;WinNTSetp&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;3、安装Fedora&#34;&gt;&lt;a href=&#34;#3、安装Fedora&#34; class=&#34;headerlink&#34; title=&#34;3、安装Fedora&#34;&gt;&lt;/a&gt;3、安装Fedora&lt;/h3&gt;&lt;h4 id=&#34;1-gt-下载Fedora&#34;&gt;&lt;a href=&#34;#1-gt-下载Fedora&#34; class=&#34;headerlink&#34; title=&#34;1&amp;gt;下载Fedora&#34;&gt;&lt;/a&gt;1&amp;gt;下载Fedora&lt;/h4&gt;&lt;p&gt; Fedora 的下载地址是:&lt;a href=&#34;https://getfedora.org/en/workstation/download/&#34;&gt;下载地址&lt;/a&gt;,&lt;code&gt;For x86_64:Fedora 33: x86_64 DVD ISO&lt;/code&gt;&lt;/p&gt;
&lt;h4 id=&#34;2-gt-放进装好Ventoy的U盘，选择Fedora-Workstation-Live-x86-64-33-1-2-iso&#34;&gt;&lt;a href=&#34;#2-gt-放进装好Ventoy的U盘，选择Fedora-Workstation-Live-x86-64-33-1-2-iso&#34; class=&#34;headerlink&#34; title=&#34;2&amp;gt; 放进装好Ventoy的U盘，选择Fedora-Workstation-Live-x86_64-33-1.2.iso&#34;&gt;&lt;/a&gt;2&amp;gt; 放进装好&lt;code&gt;Ventoy&lt;/code&gt;的U盘，选择&lt;code&gt;Fedora-Workstation-Live-x86_64-33-1.2.iso&lt;/code&gt;&lt;/h4&gt;&lt;p&gt;具体安装步骤方法参照&lt;a href=&#34;https://ywnz.com/linuxaz/6764.html&#34;&gt;云网牛站：Fedora 32系统安装&lt;/a&gt;。&lt;/p&gt;
&lt;h4 id=&#34;3-gt-安装完成后桌面展示：&#34;&gt;&lt;a href=&#34;#3-gt-安装完成后桌面展示：&#34; class=&#34;headerlink&#34; title=&#34;3&amp;gt;安装完成后桌面展示：&#34;&gt;&lt;/a&gt;3&amp;gt;安装完成后桌面展示：&lt;/h4&gt;&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8sOUtS9YZ238uG9WnyfTD4Xmb1bhBW5XcMTzJLwyyKOyUmYgBtTfgb88hFhFA8xetg!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=078690962&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;Fedora桌面&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://a1.qpic.cn/psc?/a96e2443-01e2-41c2-bab7-ebe84a7aa1d2/*PxJIR*kzvuHPyw9DCAb8hs6Yp5CdfbjTSeeJ7FKz0cfGmg.TZFC8NJGzFl3qiuUZycDyWXa4*LB3Q2dRr2*Dw!!/b&amp;amp;ek=1&amp;amp;kp=1&amp;amp;pt=0&amp;amp;bo=IAMrBCADKwQRECc!&amp;amp;tl=3&amp;amp;su=0223784754&amp;amp;tm=1609052400&amp;amp;sce=0-12-12&amp;amp;rf=2-9&#34; alt=&#34;Fedora一些程序&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;一、利用mysqldump备份与恢复命令：&#34;&gt;&lt;a href=&#34;#一、利用mysqldump备份与恢复命令：&#34; class=&#34;headerlink&#34; title=&#34;一、利用mysqldump备份与恢复命令：&#34;&gt;&lt;/a&gt;一、利用&lt;code&gt;mysqldump&lt;/code&gt;备份与恢复命令：&lt;/h2&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ sudo mysqldump -uroot -p wpDB &amp;gt; /home/yk/mysql-wpDB.dump  //备份数据库名及保存路径&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ sudo mysql -uroot  //进入数据库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [(none)]&amp;gt; create database wpDBtest; //创建测试恢复数据库,单库备份需先创建该数据库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ mysql -uroot -pyinkai wpDBtest &amp;lt; /home/yk/mysql-wpDB.dump;  //恢复数据库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注意：上诉备份方案存在一定的弊端如：用户正在执行数据操作时，数据则会丢失等情况。 &lt;/p&gt;
&lt;p&gt;解决方案：  &lt;/p&gt;
&lt;h4 id=&#34;1》在备份数据库表加上锁，保证数据的完整性。&#34;&gt;&lt;a href=&#34;#1》在备份数据库表加上锁，保证数据的完整性。&#34; class=&#34;headerlink&#34; title=&#34;1》在备份数据库表加上锁，保证数据的完整性。&#34;&gt;&lt;/a&gt;1》在备份数据库表加上锁，保证数据的完整性。&lt;/h4&gt;&lt;p&gt;&lt;code&gt;--lock-all-tables&lt;/code&gt;:请求锁定所有表&lt;br&gt;实例：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ mysqldump --databases wpDBtest --lock-all-tables &amp;gt;/home/yk/wpDBtest .sql &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--single-transaction&lt;/code&gt;:单事务，能够对&lt;code&gt;innodb&lt;/code&gt;存储引擎做热备 &lt;/p&gt;
&lt;p&gt;&lt;code&gt;--events&lt;/code&gt;:备份事件调度器代码&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--routines&lt;/code&gt;:备份存储过程和存储函数&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--triggers&lt;/code&gt;:备份触发器 &lt;/p&gt;
&lt;p&gt;备份时请求锁之后滚动日志：&lt;code&gt;--flush-logs&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;复制时同步位置标记：&lt;code&gt;--master-data=[0|1|2]&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;注意：恢复时需关闭二进制文件，恢复成功后则开启&lt;/p&gt;
&lt;p&gt;关闭二进制日志：&lt;code&gt;set session sql_log_bin=0&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;开启二进制日志：&lt;code&gt;set session sql_log_bin=1&lt;/code&gt;&lt;/p&gt;
&lt;h4 id=&#34;2》锁表备份步骤：&#34;&gt;&lt;a href=&#34;#2》锁表备份步骤：&#34; class=&#34;headerlink&#34; title=&#34;2》锁表备份步骤：&#34;&gt;&lt;/a&gt;2》锁表备份步骤：&lt;/h4&gt;&lt;h5 id=&#34;1-锁表并且给只读权限&#34;&gt;&lt;a href=&#34;#1-锁表并且给只读权限&#34; class=&#34;headerlink&#34; title=&#34;1)锁表并且给只读权限&#34;&gt;&lt;/a&gt;1)锁表并且给只读权限&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [(none)]&amp;gt;flush tables with read lock;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;2-滚动日志&#34;&gt;&lt;a href=&#34;#2-滚动日志&#34; class=&#34;headerlink&#34; title=&#34;2)滚动日志&#34;&gt;&lt;/a&gt;2)滚动日志&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [(none)]&amp;gt;flush logs;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;3-查看二进制日志信息&#34;&gt;&lt;a href=&#34;#3-查看二进制日志信息&#34; class=&#34;headerlink&#34; title=&#34;3)查看二进制日志信息&#34;&gt;&lt;/a&gt;3)查看二进制日志信息&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [(none)]&amp;gt;show master status; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;4-使用mysqldump进行数据备份&#34;&gt;&lt;a href=&#34;#4-使用mysqldump进行数据备份&#34; class=&#34;headerlink&#34; title=&#34;4)使用mysqldump进行数据备份&#34;&gt;&lt;/a&gt;4)使用&lt;code&gt;mysqldump&lt;/code&gt;进行数据备份&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ mysqldump --databases wpDBtest &amp;gt;/tmp/wpDBtest.sql&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;5-备份完成之后则需解锁&#34;&gt;&lt;a href=&#34;#5-备份完成之后则需解锁&#34; class=&#34;headerlink&#34; title=&#34;5)备份完成之后则需解锁&#34;&gt;&lt;/a&gt;5)备份完成之后则需解锁&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [(none)]&amp;gt;unlock tables; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;命令行备份实例如下：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mysqldump -p --databases wpDBtest --lock-all-tables --flush-logs &amp;gt;/home/yk/wpDBtest2.sql &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysqldump -p --databases wpDBtest --single-trasaction --flush-logs &amp;gt;/home/yk/wpDBtest3.sql &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mysqldump -p --databases wpDBtest --lock-all-tables --flush-logs --master-data=2 &amp;gt;/home/yk/wpDBtest4.sql&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;2》查看恢复的数据&#34;&gt;&lt;a href=&#34;#2》查看恢复的数据&#34; class=&#34;headerlink&#34; title=&#34;2》查看恢复的数据&#34;&gt;&lt;/a&gt;2》查看恢复的数据&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ sudo mysql -uroot  //进入数据库 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ use wpDBtest;   /选择查看数据库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [wpDBtest]&amp;gt; select * from wp_options where option_name in(&amp;quot;siteurl&amp;quot;,&amp;quot;home&amp;quot;); //查看恢复信息&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;二、用二进制日志恢复命令：&#34;&gt;&lt;a href=&#34;#二、用二进制日志恢复命令：&#34; class=&#34;headerlink&#34; title=&#34;二、用二进制日志恢复命令：&#34;&gt;&lt;/a&gt;二、用二进制日志恢复命令：&lt;/h2&gt;&lt;h3 id=&#34;1》开启binlog&#34;&gt;&lt;a href=&#34;#1》开启binlog&#34; class=&#34;headerlink&#34; title=&#34;1》开启binlog&#34;&gt;&lt;/a&gt;1》开启&lt;code&gt;binlog&lt;/code&gt;&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ sudo vim /etc/alternatives/my.cnf  //添加如下内容，开启binlog&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[mysqld]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log_bin=mysql-bin&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2》-查看log-bin是否开启&#34;&gt;&lt;a href=&#34;#2》-查看log-bin是否开启&#34; class=&#34;headerlink&#34; title=&#34;2》//查看log_bin是否开启&#34;&gt;&lt;/a&gt;2》//查看&lt;code&gt;log_bin&lt;/code&gt;是否开启&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [(none)]&amp;gt;  show variables like &amp;#x27;log_bin&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;//查看二进制&lt;code&gt;log&lt;/code&gt;，&lt;code&gt;--no-defaults&lt;/code&gt;避免出现字符问题错误&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ sudo mysqlbinlog --no-defaults /var/lib/mysql/mysql-bin.000001;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;3》测试过程&#34;&gt;&lt;a href=&#34;#3》测试过程&#34; class=&#34;headerlink&#34; title=&#34;3》测试过程&#34;&gt;&lt;/a&gt;3》测试过程&lt;/h3&gt;&lt;h4 id=&#34;1、创建测试数据库并新增表和记录&#34;&gt;&lt;a href=&#34;#1、创建测试数据库并新增表和记录&#34; class=&#34;headerlink&#34; title=&#34;1、创建测试数据库并新增表和记录&#34;&gt;&lt;/a&gt;1、创建测试数据库并新增表和记录&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [wpDBtest]&amp;gt; create database testDB;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; create table testtable (id int null, name varchar(255) null);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [(none)]&amp;gt; source /home/yk/wpDBtest-re.sql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; insert into testtable values(1,&amp;quot;xiaoming&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; insert into testtable values(2,&amp;quot;wang&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; insert into testtable values(3,&amp;quot;王&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;2、删除一条测试数据&#34;&gt;&lt;a href=&#34;#2、删除一条测试数据&#34; class=&#34;headerlink&#34; title=&#34;2、删除一条测试数据&#34;&gt;&lt;/a&gt;2、删除一条测试数据&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; delete from testtable where id =2;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;##MariaDB [testDB]&amp;gt; delete from testtable;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;##Query OK, 5 rows affected (0.027 sec)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; select * from testtable; //显示如下：&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+------+----------+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| id   | name     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+------+----------+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|    1 | xiaoming |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|    3 | 王       |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+------+----------+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2 rows in set (0.001 sec)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;3、导出二进制log为sql-database-testDB-指定导出数据库testDB的数据&#34;&gt;&lt;a href=&#34;#3、导出二进制log为sql-database-testDB-指定导出数据库testDB的数据&#34; class=&#34;headerlink&#34; title=&#34;3、导出二进制log为sql,--database=testDB 指定导出数据库testDB的数据&#34;&gt;&lt;/a&gt;3、导出二进制&lt;code&gt;log&lt;/code&gt;为&lt;code&gt;sql&lt;/code&gt;,&lt;code&gt;--database=testDB&lt;/code&gt; 指定导出数据库&lt;code&gt;testDB&lt;/code&gt;的数据&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ sudo  mysqlbinlog --no-defaults --database=testDB /var/lib/mysql/mysql-bin.000001&amp;gt;/home/yk/testDB.sql;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;4、进入-home-yk-文件夹，复制原数据并另存testDB-re-sql&#34;&gt;&lt;a href=&#34;#4、进入-home-yk-文件夹，复制原数据并另存testDB-re-sql&#34; class=&#34;headerlink&#34; title=&#34;4、进入/home/yk/文件夹，复制原数据并另存testDB-re.sql&#34;&gt;&lt;/a&gt;4、进入&lt;code&gt;/home/yk/&lt;/code&gt;文件夹，复制原数据并另存&lt;code&gt;testDB-re.sql&lt;/code&gt;&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ cp testDB.sql testDB-re.sql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ sudo vim testDB-re.sql  //打开sql文件，删除其中“delete from testtable where id =2”语句&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;5、进入mariadb，恢复数据&#34;&gt;&lt;a href=&#34;#5、进入mariadb，恢复数据&#34; class=&#34;headerlink&#34; title=&#34;5、进入mariadb，恢复数据&#34;&gt;&lt;/a&gt;5、进入&lt;code&gt;mariadb&lt;/code&gt;，恢复数据&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; source /home/yk/testDB-re.sql&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;MariaDB [testDB]&amp;gt; select * from testtable;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+------+----------+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;| id   | name     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+------+----------+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|    1 | xiaoming |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|    3 | 王       |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|    1 | xiaoming |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|    2 | wang     |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|    3 | 王       |&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;+------+----------+&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5 rows in set (0.001 sec)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;参考资料：&lt;br&gt;&lt;a href=&#34;https://blog.51cto.com/purify/1860516&#34;&gt;mariadb二进制日志和备份恢复&lt;/a&gt;&lt;/p&gt;

&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#!/usr/bin/env python&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Date : 2019-03-18 13:02:32&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Author : KK (xxxxx@xxxxx.com)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Link : http://default.com&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# @Version : $Id$&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; urllib.request &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; bs4 &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; BeautifulSoup&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#get book&amp;#x27;s chapter&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;get_chapter&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;url&lt;/span&gt;):&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; html = urllib.request.urlopen(url) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; content = html.read().decode(&lt;span class=&#34;string&#34;&gt;&amp;#x27;utf8&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; html.close()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; soup = BeautifulSoup(content, &lt;span class=&#34;string&#34;&gt;&amp;quot;lxml&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; title = soup.find(&lt;span class=&#34;string&#34;&gt;&amp;#x27;h1&amp;#x27;&lt;/span&gt;).text &lt;span class=&#34;comment&#34;&gt;#chapter title&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; text = soup.find(&lt;span class=&#34;string&#34;&gt;&amp;#x27;div&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;built_in&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;htmlContent&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#chapter content&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;comment&#34;&gt;#processing the content to get nice style&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; content = text.get_text(&lt;span class=&#34;string&#34;&gt;&amp;#x27;
&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;br/&amp;#x27;&lt;/span&gt;).replace(&lt;span class=&#34;string&#34;&gt;&amp;#x27;
&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;
 &amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; content = content.replace(&lt;span class=&#34;string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;
 &amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; title, &lt;span class=&#34;string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;+content&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;main&lt;/span&gt;():&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; books = [&lt;span class=&#34;string&#34;&gt;&amp;#x27;射雕英雄传&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;天龙八部&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;鹿鼎记&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;神雕侠侣&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;笑傲江湖&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;碧血剑&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;倚天屠龙记&amp;#x27;&lt;/span&gt;,\&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;飞狐外传&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;书剑恩仇录&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;连城诀&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;侠客行&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;越女剑&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;鸳鸯刀&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;#x27;白马啸西风&amp;#x27;&lt;/span&gt;,\&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;雪山飞狐&amp;#x27;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; order = [&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;10&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;11&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;12&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;14&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;15&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;13&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt;] &lt;span class=&#34;comment&#34;&gt;#order of books to scrapy&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;comment&#34;&gt;#list to store each book&amp;#x27;s scrapying range&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; page_range = [&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;43&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;94&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;145&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;185&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;225&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;248&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;289&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;309&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;329&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;341&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;362&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;363&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;364&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;375&lt;/span&gt;,&lt;span class=&#34;number&#34;&gt;385&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; i,book &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;enumerate&lt;/span&gt;(books):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;keyword&#34;&gt;for&lt;/span&gt; num &lt;span class=&#34;keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;range&lt;/span&gt;(page_range[i],page_range[i+&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;]):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; url = &lt;span class=&#34;string&#34;&gt;&amp;quot;http://jinyong.zuopinj.com/%s/%s.html&amp;quot;&lt;/span&gt;%(order[i],num)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; title, chapter = get_chapter(url)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;F://%s.txt&amp;#x27;&lt;/span&gt;%book, &lt;span class=&#34;string&#34;&gt;&amp;#x27;a&amp;#x27;&lt;/span&gt;, encoding=&lt;span class=&#34;string&#34;&gt;&amp;#x27;gb18030&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; f:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(book+&lt;span class=&#34;string&#34;&gt;&amp;#x27;:&amp;#x27;&lt;/span&gt;+title+&lt;span class=&#34;string&#34;&gt;&amp;#x27;--&amp;gt;写入成功！&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; f.write(title+&lt;span class=&#34;string&#34;&gt;&amp;#x27;


&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; f.write(chapter+&lt;span class=&#34;string&#34;&gt;&amp;#x27;


&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;keyword&#34;&gt;except&lt;/span&gt; Exception &lt;span class=&#34;keyword&#34;&gt;as&lt;/span&gt; e:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(e) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;全部写入完毕!&amp;#x27;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;main()&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
